-- Q1: MCQ — Easy — Using a badge scanner
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000001',
    '66666666-6666-6666-6666-666666666666',
    'easy', 'mcq',
    'At the event entrance you are given a handheld badge scanner. It beeps red every time you scan a delegate badge. What is your FIRST action?',
    'Tədbir girişində sizə əl badge skaneri verilir. Hər nümayəndə badgini skanlayanda qırmızı bip verir. İlk hərəkətiniz nə olacaq?',
    '[
        {"key": "A", "text_en": "Keep scanning and hope it fixes itself", "text_az": "Skanlamağa davam et, özü düzələr deyə ümid et"},
        {"key": "B", "text_en": "Check if the scanner is connected, restart it, and scan a test badge to confirm", "text_az": "Skanerin bağlı olub olmadığını yoxla, yenidən başlat və test badgini skanla"},
        {"key": "C", "text_en": "Immediately replace all badge scanners at the entrance", "text_az": "Girişdəki bütün skanerləri dərhal dəyişdir"},
        {"key": "D", "text_en": "Ask delegates to enter without scanning and log them manually on paper", "text_az": "Nümayəndələrdən skansız girməsini xahiş et və kağızda əl ilə qeyd et"}
    ]',
    'B',
    1.4, -1.0, 0.10,
    'Basic troubleshooting: verify connectivity first, restart the device, then test before concluding it is broken. Skipping to workarounds creates data gaps.',
    'Əsas problemin aradan qaldırılması: əvvəlcə bağlantını yoxla, cihazı yenidən başlat, sonra sınaq et. Alternativ həllərə keçmək məlumat boşluqları yaradır.',
    'Learn the 3-step tech troubleshoot loop: Check connection → Restart → Test. This solves 80% of scanner and device issues at events.',
    '3 addımlı texniki problemin həlli döngüsünü öyrən: Bağlantını yoxla → Yenidən başlat → Sına. Bu, tədbirlərdəki skanerlərin 80%-ni həll edir.'
) ON CONFLICT (id) DO NOTHING;

-- Q2: MCQ — Easy — Spreadsheet data entry
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000002',
    '66666666-6666-6666-6666-666666666666',
    'easy', 'mcq',
    'You are updating a shared Google Sheet with volunteer attendance. You accidentally delete a row with 12 names. What do you do IMMEDIATELY?',
    'Siz könüllülərin iştirakını paylaşılan Google Cədvəlinə daxil edirsiniz. Təsadüfən 12 ad olan bir sıranı silirsiniz. Dərhal nə edərsiniz?',
    '[
        {"key": "A", "text_en": "Close the browser tab and reopen — the data might come back", "text_az": "Brauzer sekmesini bağla və yenidən aç — məlumatlar gəri gələ bilər"},
        {"key": "B", "text_en": "Press Ctrl+Z (undo) immediately before doing anything else", "text_az": "Başqa bir şey etməzdən əvvəl dərhal Ctrl+Z (geri al) düyin"},
        {"key": "C", "text_en": "Notify the team and wait for someone more experienced to fix it", "text_az": "Komandanı xəbərdar et və daha təcrübəli birinin düzəltməsini gözlə"},
        {"key": "D", "text_en": "Manually re-enter the names from memory", "text_az": "Adları yaddaşından əl ilə yenidən daxil et"}
    ]',
    'B',
    1.3, -1.3, 0.12,
    'Ctrl+Z is universal undo and must be the immediate reflex. Acting before undoing risks losing the recovery window permanently.',
    'Ctrl+Z universal geri alma düyməsidir və dərhal refleks olmalıdır. Geri almadan əvvəl hərəkət etmək bərpa imkanını əbədi itirə bilər.',
    'Learn the top 5 keyboard shortcuts for every shared tool you use at events: Undo, Save, Find, Select All, Copy-Paste.',
    'Tədbirlərdə istifadə etdiyiniz hər paylaşılan alət üçün ən vacib 5 klaviatura qısa yolunu öyrən: Geri al, Saxla, Tap, Hamısını seç, Kopyala-Yapışdır.'
) ON CONFLICT (id) DO NOTHING;

-- Q3: MCQ — Easy — Walkie-talkie protocol
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000003',
    '66666666-6666-6666-6666-666666666666',
    'easy', 'mcq',
    'You need to reach your team leader urgently via walkie-talkie. Another team is already transmitting on the channel. What is the correct action?',
    'Telsiz vasitəsilə komanda liderinizə təcili çatmaq lazımdır. Başqa bir komanda artıq kanalda ötürüm edir. Doğru hərəkət hansıdır?',
    '[
        {"key": "A", "text_en": "Press transmit and speak over them — urgency takes priority", "text_az": "Ötürüm düyməsini bas və onların üstünə danış — təcilik üstünlük verir"},
        {"key": "B", "text_en": "Wait for a pause, then say your call sign and ''urgent message'' before transmitting", "text_az": "Fasilə gözlə, sonra ötürümdən əvvəl çağrı işarəni və ''təcili mesaj'' de"},
        {"key": "C", "text_en": "Switch to a different channel without notifying your team leader", "text_az": "Komanda liderinə xəbər vermədən başqa kanala keç"},
        {"key": "D", "text_en": "Send a WhatsApp message instead", "text_az": "Bunun əvəzinə WhatsApp mesajı göndər"}
    ]',
    'B',
    1.2, -1.1, 0.15,
    'Radio discipline requires waiting for a clear channel. Identifying yourself and flagging urgency ensures others yield quickly — speaking over active transmission creates noise and confusion.',
    'Radio intizamı kanalın açılmasını gözləməyi tələb edir. Özünüzü təqdim etmək və təcililiyi bildirmək başqalarının tez yer açmasını təmin edir.',
    'Before your first event with walkies: learn your team''s channel plan, call signs, and the ''Break Break'' emergency override procedure.',
    'Telsizlə ilk tədbirinizdən əvvəl: komandanızın kanal planını, çağrı işarələrini və ''Fasilə Fasilə'' fövqəladə ləğvetmə prosedurasını öyrənin.'
) ON CONFLICT (id) DO NOTHING;

-- Q4: MCQ — Medium — Registration system error under pressure
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000004',
    '66666666-6666-6666-6666-666666666666',
    'medium', 'mcq',
    'The online registration system freezes with 40 delegates queuing at your desk. The system has been unresponsive for 2 minutes. What is your BEST course of action?',
    'Online qeydiyyat sistemi masanızda 40 nümayəndə növbəyə durmuş vəziyyətdə donub. Sistem 2 dəqiqədir cavab vermir. Ən YAXŞI hərəkətiniz nədir?',
    '[
        {"key": "A", "text_en": "Keep refreshing the page every 10 seconds and ask delegates to wait", "text_az": "Hər 10 saniyədə səhifəni yenilə və nümayəndələrdən gözləmələrini xahiş et"},
        {"key": "B", "text_en": "Switch to the offline backup list immediately, log names manually, and notify your tech lead", "text_az": "Dərhal oflayn ehtiyat siyahısına keç, adları əl ilə qeyd et və texniki rəhbərinə xəbər ver"},
        {"key": "C", "text_en": "Ask all delegates to register again on their phones using the mobile app", "text_az": "Bütün nümayəndələrdən mobil tətbiqdən istifadə edərək yenidən qeydiyyatdan keçmələrini xahiş et"},
        {"key": "D", "text_en": "Close the desk and wait for IT to fix the system before continuing", "text_az": "Masanı bağla və İT sistemi düzəldənə qədər gözlə"}
    ]',
    'B',
    1.7, 0.2, 0.12,
    'Event tech resilience means having and activating a fallback immediately when primary systems fail. Keeping a queue waiting while refreshing creates bottleneck and bad attendee experience.',
    'Tədbir texnologiyasının dayanıqlılığı əsas sistemlər uğursuz olduqda dərhal ehtiyat planını işə salmaqdır. Yeniləyərkən növbəni gözlətmək tıxac və pis iştirakçı təcrübəsi yaradır.',
    'Always know the offline fallback procedure before your shift. Ask your coordinator: ''What do we do if the system goes down?'' on day one.',
    'Növbənizdən əvvəl həmişə oflayn ehtiyat prosedurasını bilin. Birinci gün koordinatorunuzdan soruşun: ''Sistem çöksə nə edirik?'''
) ON CONFLICT (id) DO NOTHING;

-- Q5: MCQ — Medium — Screen sharing / presentation support
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000005',
    '66666666-6666-6666-6666-666666666666',
    'medium', 'mcq',
    'A speaker''s laptop won''t connect to the projector 5 minutes before their session. The HDMI cable is plugged in but the screen stays black. Which troubleshooting step should you try FIRST?',
    'Natiqin noutbuku sessiyadan 5 dəqiqə əvvəl proyektora qoşulmur. HDMI kabeli qoşulub, lakin ekran qara qalır. Hansı problemin həlli addımını İLK sınamaq lazımdır?',
    '[
        {"key": "A", "text_en": "Replace the HDMI cable with a new one from the equipment room", "text_az": "HDMI kabeli avadanlıq otağından yenisi ilə əvəz et"},
        {"key": "B", "text_en": "Press the display toggle shortcut (Windows+P or Fn+F key) on the laptop to switch output mode", "text_az": "Çıxış rejimini dəyişdirmək üçün noutbukda ekran dəyişdirmə qısayolunu (Windows+P və ya Fn+F düyməsi) bas"},
        {"key": "C", "text_en": "Restart the projector from the main power panel", "text_az": "Proyektoru əsas elektrik panelindən yenidən başlat"},
        {"key": "D", "text_en": "Ask the speaker to use a different laptop", "text_az": "Natiqdən fərqli noutbukdan istifadə etməsini xahiş et"}
    ]',
    'B',
    1.9, 0.4, 0.10,
    'The display toggle is the fastest and most common fix for black screen HDMI issues — the laptop is outputting to the wrong display. Hardware swaps and restarts should follow only if software steps fail.',
    'Ekran dəyişdirmə qısayolu qara ekran HDMI problemlərinin ən sürətli və ən ümumi həllidir — noutbuk yanlış ekrana çıxış edir. Aparat dəyişimləri yalnız proqram addımları uğursuz olarsa edilməlidir.',
    'Memorize display hotkeys for Windows (Win+P), Mac (Cmd+F1), and know the 4 output modes: PC only, Duplicate, Extend, Second screen only.',
    'Windows (Win+P), Mac (Cmd+F1) üçün ekran qısayollarını əzbərlə və 4 çıxış rejimini bil: Yalnız PC, Dublikat, Genişləndir, Yalnız ikinci ekran.'
) ON CONFLICT (id) DO NOTHING;

-- Q6: MCQ — Medium — Data privacy with spreadsheets
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000006',
    '66666666-6666-6666-6666-666666666666',
    'medium', 'mcq',
    'After the event you notice the volunteer attendance spreadsheet — containing full names, phone numbers, and IDs — has been shared with "Anyone with the link can edit." What should you do?',
    'Tədbirden sonra fərq edirsiniz ki, tam adlar, telefon nömrələri və şəxsiyyət vəsiqəsi məlumatlarını ehtiva edən könüllü iştirak cədvəli "Keçid olan hər kəs redaktə edə bilər" kimi paylaşılıb. Nə etməlisiniz?',
    '[
        {"key": "A", "text_en": "It is fine — the event is over so the data is no longer sensitive", "text_az": "Bir şey deyil — tədbir bitib, ona görə məlumatlar artıq həssas deyil"},
        {"key": "B", "text_en": "Change the sharing permission to restricted immediately and inform your coordinator", "text_az": "Paylaşma icazəsini dərhal məhdudlaşdırılmışa dəyişdir və koordinatorunu xəbərdar et"},
        {"key": "C", "text_en": "Download a copy for yourself as backup before changing anything", "text_az": "Hər şeyi dəyişdirməzdən əvvəl ehtiyat nüsxə kimi özün üçün bir nüsxə yüklə"},
        {"key": "D", "text_en": "Delete the spreadsheet entirely to prevent misuse", "text_az": "Sui-istifadəni önləmək üçün cədvəli tamamilə sil"}
    ]',
    'B',
    1.8, 0.3, 0.08,
    'Personal data remains sensitive after the event. The correct action is to restrict access and report the misconfiguration — not ignore, self-copy, or delete.',
    'Şəxsi məlumatlar tədbirden sonra da həssas qalır. Düzgün hərəkət girişi məhdudlaşdırmaq və yanlış konfiqurasiyanı bildirməkdir — nəzərə almamaq, özünüzə kopyalamaq və ya silmək deyil.',
    'Before every event: confirm sharing settings on all data files are set to ''Specific people only''. Make it a pre-event checklist habit.',
    'Hər tədbirden əvvəl: bütün məlumat fayllarındakı paylaşma parametrlərinin ''Yalnız xüsusi şəxslər'' olaraq təyin edildiyini təsdiqləyin.'
) ON CONFLICT (id) DO NOTHING;

-- Q7: Open-ended — Hard — Tech setup checklist thinking
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000007',
    '66666666-6666-6666-6666-666666666666',
    'hard', 'open_ended',
    'You arrive 90 minutes before a 200-person conference to set up the tech station: 4 badge scanners, 2 registration laptops, walkie-talkies for 8 volunteers, and a live attendance spreadsheet. Describe your setup and verification process.',
    'Siz 200 nəfərlik konfransdan 90 dəqiqə əvvəl texniki stansiya qurmaq üçün gəlirsiniz: 4 badge skaneri, 2 qeydiyyat noutbuku, 8 könüllü üçün telsizlər və canlı iştirak cədvəli. Qurulum və doğrulama prosesinizi təsvir edin.',
    '[
        {"name": "systematic_order", "weight": 0.20, "keywords": ["order", "sequence", "first", "then", "priority", "step", "ardıcıl", "sıra", "əvvəl", "sonra"]},
        {"name": "test_before_live", "weight": 0.25, "keywords": ["test", "verify", "check", "scan test badge", "trial run", "sına", "yoxla", "test badgi", "sınaq"]},
        {"name": "backup_plan", "weight": 0.20, "keywords": ["backup", "offline", "paper", "fallback", "plan B", "ehtiyat", "oflayn", "kağız"]},
        {"name": "team_briefing", "weight": 0.20, "keywords": ["brief", "assign", "role", "who covers", "walkthrough", "komanda", "tapşır", "rol", "kim", "izah"]},
        {"name": "contingency_contacts", "weight": 0.15, "keywords": ["IT contact", "tech lead", "escalate", "who to call", "texniki rəhbər", "kimi çağır", "əlaqə"]}
    ]',
    2.2, 0.9, 0.0,
    'Professional tech setup combines systematic sequencing, pre-live testing of every device, a documented fallback, team briefing with role assignments, and knowing the escalation contact.',
    'Peşəkar texniki qurulum sistematik ardıcıllığı, hər cihazın canlıdan əvvəl sınanmasını, sənədləşdirilmiş ehtiyat planı, rol tapşırıqlarını ehtiva edən komanda brifinqi və eskalasiya əlaqəsini bilməyi birləşdirir.',
    'Create a personal ''tech station setup'' checklist and bring it printed to every event. A 15-item checklist takes 5 minutes and prevents 90-minute crisis recoveries.',
    'Şəxsi ''texniki stansiya qurulumu'' siyahısı hazırlayın və hər tədbirə çap olunmuş şəkildə gətirin. 15 maddəlik siyahı 5 dəqiqə çəkir və 90 dəqiqəlik böhran bərpasının qarşısını alır.'
) ON CONFLICT (id) DO NOTHING;

-- Q8: Open-ended — Hard — Communication platform failure
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000008',
    '66666666-6666-6666-6666-666666666666',
    'hard', 'open_ended',
    'Mid-event the volunteer coordination app crashes and walkie-talkie channel 2 is full of static. You are managing 6 sub-teams spread across 3 floors. How do you maintain coordination?',
    'Tədbirin ortasında könüllü koordinasiya tətbiqi çöküb və telsiz kanalı 2 statikdoludur. Siz 3 mərtəbəyə yayılmış 6 alt komandanı idarə edirsiniz. Koordinasiyanı necə qoruyarsınız?',
    '[
        {"name": "channel_switch", "weight": 0.20, "keywords": ["switch channel", "backup channel", "channel 1", "alternative frequency", "kanal dəyiş", "ehtiyat kanal"]},
        {"name": "physical_runners", "weight": 0.20, "keywords": ["runner", "messenger", "physical", "in person", "floor captain", "qaçışçı", "xəbərçi", "fiziki", "mərtəbə kapitan"]},
        {"name": "group_messaging", "weight": 0.20, "keywords": ["WhatsApp", "Telegram", "group chat", "SMS", "group message", "qrup mesaj", "qrup çat"]},
        {"name": "designate_leads", "weight": 0.20, "keywords": ["team lead", "floor lead", "point person", "delegate authority", "komanda rəhbəri", "mərtəbə rəhbəri", "cavabdeh şəxs"]},
        {"name": "status_check_cadence", "weight": 0.20, "keywords": ["check-in", "every X minutes", "status update", "regular interval", "hesabat", "hər X dəqiqə", "status"]}
    ]',
    2.3, 1.1, 0.0,
    'Multi-team coordination during tech failure requires layered communication: switch channels, activate runners, use mobile messaging, designate floor leads, and establish a regular check-in rhythm.',
    'Texniki nasazlıq zamanı çox komandanın koordinasiyası qatlı ünsiyyəti tələb edir: kanalları dəyişdir, qaçışçıları işə sal, mobil mesajlaşmadan istifadə et, mərtəbə rəhbərləri təyin et.',
    'At every event briefing, establish 3 communication layers: primary (app/walkies), secondary (group chat), tertiary (floor runners). Never rely on a single channel.',
    'Hər tədbir brifinqindəki 3 kommunikasiya qatını qurun: əsas (tətbiq/telsizlər), ikincil (qrup çatı), üçüncül (mərtəbə qaçışçıları). Heç vaxt tək kanala güvənməyin.'
) ON CONFLICT (id) DO NOTHING;

-- Q9: Open-ended — Medium — Spreadsheet formula for attendance
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000009',
    '66666666-6666-6666-6666-666666666666',
    'medium', 'open_ended',
    'You are maintaining a Google Sheet tracking 150 volunteers. Column B has volunteer names, Column C has "Present" or "Absent." Your coordinator asks for a quick count of how many are present. Describe exactly what you would type or do.',
    'Siz 150 könüllünü izləyən Google Cədvəlini idarə edirsiniz. B sütununda könüllü adları, C sütununda "Mövcud" və ya "Yoxdur" var. Koordinatorunuz neçə nəfərin mövcud olduğunu soruşur. Nə yazacağınızı və ya nə edəcəyinizi dəqiq izah edin.',
    '[
        {"name": "countif_formula", "weight": 0.40, "keywords": ["COUNTIF", "countif", "=COUNTIF", "formula", "düstur", "COUNTIF funksiyası"]},
        {"name": "range_specification", "weight": 0.25, "keywords": ["C:C", "C2:C151", "range", "sütun", "diapazon", "aralıq"]},
        {"name": "criteria_present", "weight": 0.25, "keywords": ["Present", "\"Present\"", "Mövcud", "meyar", "criteria", "şərt"]},
        {"name": "result_communication", "weight": 0.10, "keywords": ["tell coordinator", "share result", "copy", "report", "bildirmək", "nəticəni paylaş"]}
    ]',
    1.8, 0.1, 0.0,
    'COUNTIF(C:C,"Present") is the correct formula. Knowing basic spreadsheet functions is essential for fast, accurate event reporting.',
    'COUNTIF(C:C,"Present") düzgün düsturdur. Əsas cədvəl funksiyalarını bilmək sürətli və dəqiq tədbir hesabatı üçün vacibdir.',
    'Learn 5 essential Google Sheets functions for events: COUNTIF, SUM, FILTER, SORT, and VLOOKUP. Practice with a dummy volunteer list before your next event.',
    'Tədbirlər üçün 5 vacib Google Cədvəl funksiyasını öyrən: COUNTIF, SUM, FILTER, SORT və VLOOKUP. Növbəti tədbirinizdən əvvəl süni könüllü siyahısı ilə məşq edin.'
) ON CONFLICT (id) DO NOTHING;

-- Q10: Open-ended — Hard — Digital onboarding of new volunteers
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '60000001-0000-0000-0000-000000000010',
    '66666666-6666-6666-6666-666666666666',
    'hard', 'open_ended',
    'Ten new volunteers arrive and have never used the event management platform your organization uses. You have 20 minutes to get all of them operational before doors open. Describe your onboarding approach.',
    'On yeni könüllü gəlir və heç biri təşkilatınızın istifadə etdiyi tədbir idarəetmə platformasından xəbərdar deyil. Qapılar açılmadan əvvəl hamısını 20 dəqiqə ərzində əməliyyata hazır etməlisiniz. Onboarding yanaşmanızı izah edin.',
    '[
        {"name": "group_demo", "weight": 0.25, "keywords": ["demo", "show", "screen", "walkthrough", "demonstrate", "nümayiş", "göstər", "ekran", "izah"]},
        {"name": "prioritize_essentials", "weight": 0.25, "keywords": ["essential", "key functions", "only what they need", "minimum", "prioritize", "vacib", "əsas funksiyalar", "minimal"]},
        {"name": "buddy_system", "weight": 0.20, "keywords": ["pair", "buddy", "experienced", "mentor", "partner", "cüt", "yoldaş", "təcrübəli", "mentor"]},
        {"name": "quick_reference", "weight": 0.15, "keywords": ["cheat sheet", "guide", "reference card", "printed", "qısa bələdçi", "istinad kart", "çap"]},
        {"name": "check_understanding", "weight": 0.15, "keywords": ["ask them to try", "confirm", "practice scan", "test", "sına", "yoxla", "sınaq skanı", "təsdiqlə"]}
    ]',
    2.1, 0.8, 0.0,
    'Effective rapid tech onboarding uses group demo of essentials only, a buddy system for 1-on-1 support, a quick reference card, and a confirmation test before going live.',
    'Effektiv sürətli texniki onboarding yalnız əsasların qrup nümayişindən, fərdi dəstək üçün yoldaş sistemindən, qısa istinad kartından və canlıya keçməzdən əvvəl təsdiqləmə testindən istifadə edir.',
    'Prepare a one-page ''platform quick start'' guide for your event tools. A good guide reduces onboarding from 20 minutes to 7.',
    'Tədbir alətləriniz üçün bir səhifəlik ''platformaya sürətli başlama'' bələdçisi hazırlayın. Yaxşı bir bələdçi onboardinqi 20 dəqiqədən 7-yə endirər.'
) ON CONFLICT (id) DO NOTHING;


-- =============================================================================
-- ADAPTABILITY COMPETENCY (10 questions)
-- competency_id: 77777777-7777-7777-7777-777777777777
-- UUID prefix: d0000001-0000-0000-0000-00000000000N
-- Mix: 6 MCQ + 4 open_ended | 3 easy, 4 medium, 3 hard
-- =============================================================================

-- Q1: MCQ — Easy — Last-minute role change
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000001',
    '77777777-7777-7777-7777-777777777777',
    'easy', 'mcq',
    '30 minutes before your shift begins, your coordinator tells you that instead of working registration you are now needed at the information desk. You have never done that role before. What is your FIRST reaction?',
    'Növbəniz başlamazdan 30 dəqiqə əvvəl koordinatorunuz sizə qeydiyyat əvəzinə indi məlumat masasında lazım olduğunuzu bildirir. Bu rolu əvvəllər heç etməmisiniz. İLK reaksiyanız nədir?',
    '[
        {"key": "A", "text_en": "Refuse — you prepared for registration and switching is unfair", "text_az": "İmtina et — qeydiyyata hazırlaşmışdın, dəyişmək ədalətsizdir"},
        {"key": "B", "text_en": "Accept, ask for a quick briefing on the information desk responsibilities, and get ready", "text_az": "Qəbul et, məlumat masasının vəzifələri haqqında qısa brifinq istə və hazırlaş"},
        {"key": "C", "text_en": "Accept but do the role exactly as you would have done registration", "text_az": "Qəbul et amma rolu qeydiyyatı edəcəyin kimi et"},
        {"key": "D", "text_en": "Accept silently and figure it out on your own without asking questions", "text_az": "Sükutla qəbul et və sual vermədən özbaşına anlayarsan"}
    ]',
    'B',
    1.3, -1.2, 0.12,
    'Adaptability means accepting change positively AND seeking the information needed to perform well in the new role. Silent acceptance without preparation leads to errors.',
    'Uyğunlaşma dəyişikliyi müsbət qəbul etmək VƏ yeni rolu yaxşı yerinə yetirmək üçün lazımi məlumatı axtarmaq deməkdir. Hazırlıqsız sükutla qəbul etmək səhvlərə gətirib çıxarır.',
    'Build a habit: when given a new role, ask 3 questions before starting — What is the priority task? Who do I report to? What does ''done well'' look like?',
    'Bir vərdiş formalaşdır: yeni rol verildikcə başlamazdan əvvəl 3 sual ver — Prioritet tapşırıq nədir? Kimə hesabat verirəm? ''Yaxşı yerinə yetirilmiş'' necə görünür?'
) ON CONFLICT (id) DO NOTHING;

-- Q2: MCQ — Easy — Unexpected schedule delay
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000002',
    '77777777-7777-7777-7777-777777777777',
    'easy', 'mcq',
    'A keynote speaker is 45 minutes late. The audience is in the hall and growing restless. Your coordinator has not given you any instructions yet. What do you do?',
    'Əsas natiq 45 dəqiqə gecikir. Tamaşaçılar saldadır və narahat olmağa başlayır. Koordinatorunuz hələ heç bir göstəriş verməyib. Nə edirsiniz?',
    '[
        {"key": "A", "text_en": "Do nothing — wait for instructions before acting", "text_az": "Heç nə etmə — hərəkət etməzdən əvvəl göstərişləri gözlə"},
        {"key": "B", "text_en": "Circulate among the audience to stay visible, answer questions calmly, and proactively check in with your coordinator for updates", "text_az": "Tamaşaçılar arasında gəz, görünən ol, sualları sakit cavabla və koordinatoru aktiv şəkildə yeniləmə üçün yoxla"},
        {"key": "C", "text_en": "Announce to the audience that the speaker will arrive soon", "text_az": "Tamaşaçılara natiqi tezliklə gəlib çıxacağını elan et"},
        {"key": "D", "text_en": "Suggest rescheduling to the next day", "text_az": "Sabahki günə keçirməyi təklif et"}
    ]',
    'B',
    1.4, -1.0, 0.10,
    'Proactive presence without overstepping authority: staying visible and calm reassures the audience while checking in keeps you informed to act when instruction arrives.',
    'Səlahiyyəti aşmadan proaktiv mövcudluq: görünən və sakit qalmaq auditoriyaya arxayınlıq verir, yoxlama isə göstəriş gəldikdə hərəkət etmək üçün sizi məlumatlı saxlayır.',
    'During any unscheduled gap, deploy the WAIT principle: Watch (what is happening?), Assess (what is needed?), Inform (your coordinator), Take small positive action.',
    'Planlaşdırılmamış hər fasilədə WAIT prinsipini tətbiq edin: İzlə (nə baş verir?), Qiymətləndir (nəyə ehtiyac var?), Xəbər ver (koordinatora), Kiçik müsbət addım at.'
) ON CONFLICT (id) DO NOTHING;

-- Q3: MCQ — Easy — Covering an absent teammate
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000003',
    '77777777-7777-7777-7777-777777777777',
    'easy', 'mcq',
    'A teammate who handles the VIP lounge does not show up for their shift. You are asked to cover them in addition to your own role for 2 hours. How do you handle this?',
    'VIP lounjunu idarə edən bir komanda üzvü növbəsinə gəlmir. Sizdən 2 saat ərzində öz rolunuza əlavə olaraq onları əvəz etməyiniz xahiş edilir. Bunu necə idarə edirsiniz?',
    '[
        {"key": "A", "text_en": "Decline — it is not your responsibility and doing two roles is not fair", "text_az": "İmtina et — bu sənin məsuliyyətin deyil və iki rol etmək ədalətsizdir"},
        {"key": "B", "text_en": "Accept, get a quick handover on VIP lounge priorities, communicate the coverage to your coordinator, and manage your time across both roles", "text_az": "Qəbul et, VIP lounjunun prioritetləri haqqında qısa ötürüm al, koordinatora bildir və hər iki rola vaxtını böl"},
        {"key": "C", "text_en": "Accept and abandon your original role entirely to focus on VIP", "text_az": "Qəbul et və VIP-a diqqət yetirmək üçün orijinal rolunu tamamilə tərk et"},
        {"key": "D", "text_en": "Accept but make a formal complaint to HR about the absent teammate first", "text_az": "Qəbul et amma əvvəlcə qeyri-mövcud komanda üzvü haqqında HR-a rəsmi şikayət et"}
    ]',
    'B',
    1.5, -0.8, 0.12,
    'Team coverage requires accepting flexibly, getting the minimum context needed, keeping coordination informed, and time-managing both roles rather than dropping one.',
    'Komanda əhatəsi çevik qəbul etməyi, lazımi minimum konteksti almağı, koordinatoru məlumatlı saxlamağı və birini atmaqdansa hər iki rola vaxt bölüşdürməyi tələb edir.',
    'Build a habit of doing a 5-minute ''role shadowing'' of at least one teammate per event. This gives you enough context to step in when needed.',
    'Hər tədbirde ən azı bir komanda üzvünün 5 dəqiqəlik ''rol kölgəsi'' vərdiş edin. Bu, lazım olduqda üstlənmək üçün kifayət qədər kontekst verir.'
) ON CONFLICT (id) DO NOTHING;

-- Q4: MCQ — Medium — Venue change on event day
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000004',
    '77777777-7777-7777-7777-777777777777',
    'medium', 'mcq',
    'Two hours before an outdoor cultural event, heavy rain forces a move indoors to a smaller venue. Your team has 30 minutes to reconfigure. You are the most senior volunteer present. What do you do?',
    'Açıq havada mədəni tədbirden 2 saat əvvəl güclü yağış daha kiçik qapalı bir məkana keçməyi məcbur edir. Komandanızın yenidən konfiqurasiya üçün 30 dəqiqəsi var. Siz mövcud ən böyük könüllüsünüz. Nə edirsiniz?',
    '[
        {"key": "A", "text_en": "Wait for the event manager to give everyone instructions before touching anything", "text_az": "Heç bir şeyə toxunmadan əvvəl tədbir menecerinin hamıya göstəriş verməsini gözlə"},
        {"key": "B", "text_en": "Immediately assess the new space, assign volunteers to priority tasks (signage, seating, tech), communicate the plan clearly, and report status to the event manager", "text_az": "Dərhal yeni məkanı qiymətləndir, könüllülərə prioritet tapşırıqlar ver (lövhəçilik, oturacaqlar, texnologiya), planı aydın bildirin, vəziyyəti tədbir menecerinə bildirin"},
        {"key": "C", "text_en": "Suggest cancelling the event given the difficulty of the situation", "text_az": "Vəziyyətin çətinliyini nəzərə alaraq tədbirlerin ləğvini təklif et"},
        {"key": "D", "text_en": "Focus only on the tech setup and leave room configuration to others", "text_az": "Yalnız texniki quruluma diqqət yetir, otaq konfiqurasiyasını başqalarına burax"}
    ]',
    'B',
    2.0, 0.3, 0.08,
    'Senior adaptability means taking charge with a structured plan under time pressure — assessing, delegating, communicating upward, and not waiting for perfect conditions.',
    'Böyük uyğunlaşma vaxt təzyiqi altında strukturlaşdırılmış planla məsuliyyəti götürmək deməkdir — qiymətləndir, tapşır, yuxarıya bil, mükəmməl şərtləri gözləmə.',
    'Practice the OODA loop for crisis response: Observe → Orient → Decide → Act. Great volunteers complete this loop in under 60 seconds.',
    'Böhran müdafiəsi üçün OODA döngüsünü məşq edin: Müşahidə et → İstiqamətlən → Qərar ver → Hərəkət et. Böyük könüllülər bu döngüsü 60 saniyədən az müddətdə tamamlayır.'
) ON CONFLICT (id) DO NOTHING;

-- Q5: MCQ — Medium — Task overload mid-event
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000005',
    '77777777-7777-7777-7777-777777777777',
    'medium', 'mcq',
    'During a busy event you simultaneously receive: a coordinator asking for an updated headcount, a delegate needing directions, and a walkie-talkie call reporting a tech issue at stage B. You cannot do all three immediately. What do you do?',
    'Gərgin bir tədbir zamanı eyni vaxtda alırsınız: güncəllenmiş baş sayımı istəyən koordinator, yol göstərici istəyən nümayəndə və B sənədindəki texniki problemi bildirən telsiz zəngi. Hamısını dərhal edə bilmirsiniz. Nə edirsiniz?',
    '[
        {"key": "A", "text_en": "Handle them in the order received regardless of urgency", "text_az": "Təcillilikdən asılı olmayaraq alındığı sırayla idarə et"},
        {"key": "B", "text_en": "Quickly triage: acknowledge all three, prioritize the tech issue (operational impact), give the delegate 10-second directions, and send the headcount via a quick message", "text_az": "Tez triaj et: hər üçünü tanı, texniki problemi prioritetləşdir (əməliyyat təsiri), nümayəndəyə 10 saniyə yol göstər, baş sayımını qısa mesajla göndər"},
        {"key": "C", "text_en": "Focus only on the coordinator — they are highest authority", "text_az": "Yalnız koordinatora diqqət yetir — onlar ən yüksək səlahiyyətdir"},
        {"key": "D", "text_en": "Tell everyone you need 5 minutes before responding", "text_az": "Hamıya cavab verməzdən əvvəl 5 dəqiqəyə ehtiyacın olduğunu de"}
    ]',
    'B',
    1.9, 0.5, 0.10,
    'Real adaptability includes real-time prioritization. Stage tech failure has operational cascade risk; immediate acknowledgment of all three prevents anyone feeling ignored while you triage.',
    'Həqiqi uyğunlaşma real vaxt prioritetləşdirməni əhatə edir. Səhnə texniki nasazlığının əməliyyat kaskad riski var; hamısının dərhal tanınması triaj edərkən heç kimin nəzərə alınmadığını hiss etməsinin qarşısını alır.',
    'Learn triage: Safety issues → Operational blockers → Coordinator requests → Delegate comfort. This order works for 95% of volunteer situations.',
    'Triajı öyrən: Təhlükəsizlik məsələləri → Əməliyyat maneçiləri → Koordinator tələbləri → Nümayəndə rahatlığı. Bu sıra könüllü vəziyyətlərinin 95%-i üçün işləyir.'
) ON CONFLICT (id) DO NOTHING;

-- Q6: MCQ — Medium — SJT: Coping with failure under pressure
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    is_sjt_reliability,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000006',
    '77777777-7777-7777-7777-777777777777',
    'medium', 'mcq',
    'You made an error in the badge printing system and 25 badges came out with wrong names. The event starts in 20 minutes. How do you feel and what do you do?',
    'Badge çap sisteminde xəta etdiniz və 25 badge yanlış adlarla çıxdı. Tədbir 20 dəqiqəyə başlayır. Özünüzü necə hiss edirsiniz və nə edirsiniz?',
    '[
        {"key": "A", "text_en": "Panic, feel ashamed, and hide the error hoping no one notices", "text_az": "Çaxnaş, utanma hissi keçir və heç kim fərq etməsin deyə xətanı gizlə"},
        {"key": "B", "text_en": "Feel stressed but immediately report the error, assess how many can be reprinted in time, and start reprinting the highest-priority ones first", "text_az": "Gərginlik hissi et amma dərhal xətanı bildir, neçəsinin vaxtında yenidən çap edilə biləcəyini qiymətləndir və ən prioritet olanlardan başla"},
        {"key": "C", "text_en": "Distribute the wrong badges anyway and explain at the door", "text_az": "Yanlış badgeləri yenə də paylayın və qapıda izah edin"},
        {"key": "D", "text_en": "Ask a colleague to report it so you avoid blame", "text_az": "Məsuliyyətdən qaçmaq üçün bir həmkarından bildirməsini xahiş et"}
    ]',
    'B',
    2.0, 0.2, 0.08,
    TRUE,
    'Adaptability under failure means: acknowledge the mistake quickly, assess damage, take immediate corrective action, and prioritize impact reduction. Hiding errors destroys trust.',
    'Uğursuzluq altında uyğunlaşma deməkdir: xətanı tez qəbul et, zərəri qiymətləndir, dərhal düzəldici addım at, təsiri azaltmağa prioritet ver. Xətaları gizlətmək güvəni məhv edir.',
    'Mistakes at events are normal — your response to them defines your reputation. Practice saying: ''I made an error. Here is my fix plan.'' in 10 seconds.',
    'Tədbirlərdəki səhvlər normaldır — onlara verdiyin reaksiya nüfuzunu müəyyən edir. 10 saniyədə deyilməni məşq edin: ''Bir xəta etdim. Budur mənim düzəliş planım.'''
) ON CONFLICT (id) DO NOTHING;

-- Q7: Open-ended — Hard — Multi-crisis scenario
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000007',
    '77777777-7777-7777-7777-777777777777',
    'hard', 'open_ended',
    'During a 3-day international forum: Day 1 — the keynote room floods; Day 2 — 40% of your volunteer team calls in sick; Day 3 — the event software crashes mid-session. You were team lead throughout. Describe how you adapted each day.',
    '3 günlük beynəlxalq forumda: 1-ci gün — əsas natiq otağı su basır; 2-ci gün — könüllü komandanızın 40%-i xəstəlik bildirdi; 3-cü gün — tədbir proqramı session zamanı çöküb. Bütün bu müddət ərzində komanda rəhbəri idiniz. Hər gün necə uyğunlaşdığınızı izah edin.',
    '[
        {"name": "immediate_containment", "weight": 0.20, "keywords": ["move", "relocate", "alternative room", "quick fix", "contain", "köçür", "alternativ otaq", "sürətli həll", "idarə et"]},
        {"name": "resource_reallocation", "weight": 0.25, "keywords": ["redistribute", "reassign", "prioritize tasks", "do more with less", "yenidən bölüşdür", "prioritetlər", "az ilə çox", "tapşırıqları"]},
        {"name": "communication_up_and_down", "weight": 0.20, "keywords": ["inform organizer", "brief team", "update", "transparent", "organizer", "tədbir", "komandaya", "şəffaf", "yeniləmə"]},
        {"name": "calm_tone", "weight": 0.15, "keywords": ["calm", "composed", "reassure", "steady", "sakit", "arxayın", "möhkəm", "təmkin"]},
        {"name": "post_day_review", "weight": 0.20, "keywords": ["review", "debrief", "what worked", "lesson", "next day plan", "nəzərdən keçir", "brifing", "nə işlədi", "dərs", "növbəti gün"]}
    ]',
    2.4, 1.2, 0.0,
    'Elite adaptability across multiple days requires crisis containment, dynamic resource reallocation, clear communication in both directions, sustained calm leadership, and daily debriefs to improve each day.',
    'Bir neçə gün ərzində elit uyğunlaşma böhranın idarə edilməsini, dinamik resurs yenidən bölüşdürülməsini, hər iki istiqamətdə aydın ünsiyyəti, davamlı sakit liderliyi və hər günü yaxşılaşdırmaq üçün günlük brifing tələb edir.',
    'After every multi-day event, write a 3-line retrospective: What broke? How did I adapt? What would I do differently? This habit builds elite crisis intuition.',
    'Hər çox günlük tədbirden sonra 3 cümlə retrospektiv yazın: Nə sındı? Necə uyğunlaşdım? Nəyi fərqli edərdim? Bu vərdiş elit böhran intuisiyası formalaşdırır.'
) ON CONFLICT (id) DO NOTHING;

-- Q8: Open-ended — Hard — Adapting communication style
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000008',
    '77777777-7777-7777-7777-777777777777',
    'hard', 'open_ended',
    'In one afternoon you must guide: (1) a group of senior government officials to a protocol lounge, (2) a group of excited university students to a workshop, (3) a visually impaired delegate to their session room. Describe how you adapt your approach for each.',
    'Bir günortadan sonra bunları təmin etməlisiniz: (1) böyük dövlət məmurları qrupunu protokol lounjuna aparın, (2) həvəsli universitet tələbələri qrupunu seminara aparın, (3) görmə qabiliyyəti məhdud nümayəndəni sessiya otağına aparın. Hər biri üçün yanaşmanızı necə uyğunlaşdıracağınızı izah edin.',
    '[
        {"name": "tone_adjustment", "weight": 0.25, "keywords": ["formal", "casual", "respectful", "tone", "language", "rəsmi", "qeyri-rəsmi", "hörmətli", "ton", "dil"]},
        {"name": "pace_adjustment", "weight": 0.20, "keywords": ["pace", "speed", "slow down", "keep up", "tempo", "sürət", "yavaşla", "addım uydur"]},
        {"name": "accessibility_awareness", "weight": 0.30, "keywords": ["guide", "elbow", "verbal cue", "describe", "assist", "bələdçilik", "dirsək", "şifahi", "tanıt", "kömək"]},
        {"name": "group_vs_individual", "weight": 0.25, "keywords": ["group", "individual", "one-on-one", "crowd", "personal", "qrup", "fərdi", "şəxsi", "kütlə"]}
    ]',
    2.3, 1.0, 0.0,
    'Adaptability in communication means reading each audience and shifting tone, pace, formality, and physical support without being asked — proactively meeting each person where they are.',
    'Ünsiyyətdə uyğunlaşma hər auditoriyaya oxumaq və ton, sürət, rəsmilik və fiziki dəstəyi xahiş edilmədən dəyişdirmək deməkdir — hər insanı olduğu yerdə proaktiv şəkildə qarşılamaq.',
    'Practice code-switching: deliver the same information in 3 different styles — formal, casual, and simplified. This builds the muscle for rapid audience adaptation.',
    'Kod dəyişimini məşq edin: eyni məlumatı 3 fərqli üslubda çatdırın — rəsmi, qeyri-rəsmi və sadələşdirilmiş. Bu, sürətli auditoriyanın uyğunlaşması üçün əzələ formalaşdırır.'
) ON CONFLICT (id) DO NOTHING;

-- Q9: Open-ended — Medium — Sudden task unfamiliarity
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000009',
    '77777777-7777-7777-7777-777777777777',
    'medium', 'open_ended',
    'You are assigned to manage social media live updates for the event — a task you have never done before and were not told about until 1 hour before. Describe how you would approach this.',
    'Sizə tədbir üçün sosial media canlı yeniləmələrini idarə etmək tapşırılır — bu, əvvəllər heç etmədiyiniz bir tapşırıqdır və 1 saat əvvələ qədər xəbərdar edilmədiniz. Bunu necə yaxınlaşacağınızı izah edin.',
    '[
        {"name": "rapid_learning", "weight": 0.25, "keywords": ["ask", "learn", "find out", "what platform", "who to follow", "soruş", "öyrən", "hansı platform", "kimi izlə"]},
        {"name": "content_strategy", "weight": 0.25, "keywords": ["what to post", "highlights", "key moments", "approval", "nə paylaş", "əsas anlar", "təsdiq", "məzmun"]},
        {"name": "manage_expectations", "weight": 0.25, "keywords": ["honest", "tell coordinator", "first time", "best effort", "dürüst", "koordinatora de", "ilk dəfə", "ən yaxşı cəhd"]},
        {"name": "improvise_structure", "weight": 0.25, "keywords": ["template", "plan", "schedule posts", "organize", "şablon", "plan", "planlaşdır", "organize et"]}
    ]',
    1.9, 0.4, 0.0,
    'Handling an unfamiliar task under time pressure requires rapid information gathering, honest expectation management with your coordinator, and improvising a minimum viable structure.',
    'Vaxt təzyiqi altında tanımadığınız bir tapşırığı yerinə yetirmək sürətli məlumat toplama, koordinatora dürüst gözləntilər bildirmə və minimum canlı struktur yaratmağı tələb edir.',
    'Add unfamiliar tasks to your post-event learning list. Every event where you are stretched builds a new skill. Track your growth across 5+ events.',
    'Tanımadığınız tapşırıqları sonradan öyrənmə siyahınıza əlavə edin. Uzandığınız hər tədbir yeni bacarıq formalaşdırır. 5+ tədbirde böyümənizi izləyin.'
) ON CONFLICT (id) DO NOTHING;

-- Q10: Open-ended — Hard — Personal plans vs event emergency
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    is_sjt_reliability,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    'd0000001-0000-0000-0000-000000000010',
    '77777777-7777-7777-7777-777777777777',
    'hard', 'open_ended',
    'Your shift officially ends at 18:00. At 17:45 a major incident occurs — a key volunteer team leader is injured and cannot continue. You have dinner plans at 19:00 that you cannot easily cancel. Describe how you navigate this situation.',
    'Növbəniz rəsmi olaraq 18:00-da bitir. 17:45-da böyük bir hadisə baş verir — əsas könüllü komanda lideri yaralanır və davam edə bilmir. Saat 19:00-da asanlıqla ləğv edə bilmədiyiniz nahar planlarınız var. Bu vəziyyəti necə idarə edəcəyinizi izah edin.',
    '[
        {"name": "immediate_response", "weight": 0.30, "keywords": ["stay", "help", "step up", "cover", "remain", "qal", "kömək et", "üstün", "əvəz et", "qalır"]},
        {"name": "communicate_personal_constraint", "weight": 0.25, "keywords": ["honest", "tell coordinator", "19:00 deadline", "until when", "dürüst", "koordinatora de", "19:00 son vaxt", "nə vaxta qədər"]},
        {"name": "find_handover", "weight": 0.25, "keywords": ["find replacement", "handover", "brief someone", "who else", "əvəzedici tap", "ötürüm", "kimi xəbərdar et", "başqa kim"]},
        {"name": "balance_acknowledgment", "weight": 0.20, "keywords": ["balance", "both important", "team first", "communicate limits", "balans", "ikisi də", "komanda önce", "limitlər"]}
    ]',
    2.2, 1.1, 0.0,
    TRUE,
    'Adaptability includes being honest about your real constraints while doing the most you can within them. Staying until a handover is found, then handing over cleanly, shows both adaptability and integrity.',
    'Uyğunlaşma real məhdudiyyətləriniz haqqında dürüst olmağı, eyni zamanda içlərindən mümkün olan maksimumu etməyi əhatə edir. Ötürüm tapılana qədər qalmaq, sonra təmiz ötürüm etmək həm uyğunlaşmanı, həm də bütövlüyü göstərir.',
    'Know your boundaries before events start — and communicate them clearly at briefing. ''I can stay until 19:00 if needed'' is valuable information your coordinator needs.',
    'Tədbirler başlamazdan əvvəl hüdudlarınızı bilin — brifinqdə aydın bildirin. ''Lazım olsa 19:00-a qədər qala bilərəm'' — bu koordinatorunuzun ehtiyac duyduğu dəyərli məlumatdır.'
) ON CONFLICT (id) DO NOTHING;


-- =============================================================================
-- EMPATHY & SAFEGUARDING COMPETENCY (10 questions)
-- competency_id: 88888888-8888-8888-8888-888888888888
-- UUID prefix: s0000001-0000-0000-0000-00000000000N
-- Mix: 6 MCQ + 4 open_ended | 3 easy, 4 medium, 3 hard
-- =============================================================================

-- Q1: MCQ — Easy — Recognizing distress
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000001',
    '88888888-8888-8888-8888-888888888888',
    'easy', 'mcq',
    'While monitoring the event hall you notice an attendee sitting alone in a corner, visibly shaking and looking pale. What is your FIRST action?',
    'Tədbir salonunu izləyərkən bir küncdə tək oturan, açıq şəkildə titrəyən və solğun görünən bir iştirakçı görürsünüz. İLK hərəkətiniz nədir?',
    '[
        {"key": "A", "text_en": "Ignore it — they are probably just tired", "text_az": "Nəzərə alma — yəqin ki sadəcə yorğundur"},
        {"key": "B", "text_en": "Approach calmly, introduce yourself, and gently ask if they are okay and if they need anything", "text_az": "Sakit şəkildə yaxınlaş, özünü tanıt, nəzakətlə yaxşı olub olmadığını və bir şeyə ehtiyac duyub duymadığını soruş"},
        {"key": "C", "text_en": "Announce over the PA system asking if anyone knows this person", "text_az": "Bu şəxsi tanıyan var mı deyə PA sistemi vasitəsilə elan et"},
        {"key": "D", "text_en": "Take a photo and send it to the event coordinator to handle", "text_az": "Foto çəkin və tədbir koordinatoruna göndərin ki, idarə etsin"}
    ]',
    'B',
    1.4, -1.3, 0.10,
    'A calm, personal approach respects the person''s dignity. Public announcements and photo-sharing violate privacy and can increase distress. Always check in directly first.',
    'Sakit, şəxsi yanaşma insanın ləyaqətinə hörmət göstərir. İctimai elanlar və foto paylaşmaq məxfiliyi pozur və narahatlığı artıra bilər. Həmişə əvvəlcə birbaşa yoxlayın.',
    'Learn the 5 signs of distress: shaking, pallor, rapid breathing, confusion, withdrawal. Recognizing them early allows gentle, timely intervention.',
    'Narahatlığın 5 əlamətini öyrənin: titrəmə, solğunluq, sürətli nəfəs, çaşqınlıq, çəkilmə. Onları erkən tanımaq yumşaq, vaxtında müdaxiləyə imkan verir.'
) ON CONFLICT (id) DO NOTHING;

-- Q2: MCQ — Easy — Child safeguarding at events
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000002',
    '88888888-8888-8888-8888-888888888888',
    'easy', 'mcq',
    'A child, approximately 8 years old, approaches you at the event and says they cannot find their parent. What do you do?',
    'Tədbirdə, təxminən 8 yaşında bir uşaq sizə yaxınlaşır və valideynini tapa bilmədiyini söyləyir. Nə edirsiniz?',
    '[
        {"key": "A", "text_en": "Tell the child to stay where they are and you will send someone to help", "text_az": "Uşağa olduğu yerdə qalmasını söylə, kömək edəcək birini göndərəcəksən"},
        {"key": "B", "text_en": "Stay with the child, take them to a safe visible location, notify your coordinator and security, and ask the child''s name and parent description", "text_az": "Uşaqla qal, onu təhlükəsiz görünən bir yerə apar, koordinatoru və təhlükəsizliyi xəbərdar et, uşağın adını və valideyinin təsvirini soruş"},
        {"key": "C", "text_en": "Ask the child to wait at the entrance and you will make an announcement", "text_az": "Uşaqdan girişdə gözləməsini xahiş et, elan edəcəksən"},
        {"key": "D", "text_en": "Walk the venue searching for the parent yourself with the child", "text_az": "Uşaqla birlikdə valideynini özün axtararaq məkanı gəz"}
    ]',
    'B',
    1.5, -1.0, 0.08,
    'Child safeguarding requires: never leaving the child alone, taking them to a safe visible spot, immediately involving security and your coordinator, and gathering identification information.',
    'Uşağın qorunması tələb edir: uşağı heç vaxt tək buraxmamaq, onu təhlükəsiz görünən yerə aparmaq, dərhal təhlükəsizliyi və koordinatoru cəlb etmək, identifikasiya məlumatı toplamaq.',
    'At every event with children present: identify the designated child protection officer before your shift starts and know how to reach them immediately.',
    'Uşaqların iştirak etdiyi hər tədbirde: növbəniz başlamazdan əvvəl təyin edilmiş uşaq mühafizəsi məmurunu müəyyənləşdirin və dərhal onlarla əlaqəyə keçməyi bilin.'
) ON CONFLICT (id) DO NOTHING;

-- Q3: MCQ — Easy — Respecting cultural and religious needs
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000003',
    '88888888-8888-8888-8888-888888888888',
    'easy', 'mcq',
    'An attendee asks if there is a quiet space where they can pray during the event. You are not aware of any designated prayer room. What do you do?',
    'Bir iştirakçı tədbirde namaz qıla biləcəyi sakit bir yer olub olmadığını soruşur. Ayrılmış namazxana haqqında məlumatınız yoxdur. Nə edirsiniz?',
    '[
        {"key": "A", "text_en": "Tell them there is no such room and they should have planned ahead", "text_az": "Belə bir otağın olmadığını söylə, əvvəlcədən planlaşdırmalıydılar"},
        {"key": "B", "text_en": "Acknowledge their need respectfully, check with your coordinator for any available quiet space, and escort them there or provide directions", "text_az": "Ehtiyaclarını hörmətlə qəbul et, koordinatorunla mövcud sakit yer üçün yoxla, oraya aparın və ya yol göstərin"},
        {"key": "C", "text_en": "Suggest they use the bathroom as it is the quietest private space", "text_az": "Ən sakit özəl yer olduğu üçün hamam otağını istifadə etmələrini təklif et"},
        {"key": "D", "text_en": "Ignore the request — accommodating religious needs is not a volunteer role", "text_az": "Tələbi nəzərə alma — dini ehtiyacları qarşılamaq könüllü rolu deyil"}
    ]',
    'B',
    1.3, -1.1, 0.12,
    'Respecting religious and cultural needs is core to empathy. Volunteers who dismiss these requests damage inclusion and trust. Always check for solutions before saying ''no''.',
    'Dini və mədəni ehtiyaclara hörmət empatinin əsasıdır. Bu xahişləri rədd edən könüllülər daxilolma və güvəni zədələyir. ''Xeyr'' demədən əvvəl həmişə həll yolları axtarın.',
    'Before major events: learn the faith-observance schedule (prayer times, fasting dates) and proactively communicate available accommodation options to your team.',
    'Böyük tədbirlerden əvvəl: inanc müşahidə cədvəlini (namaz vaxtları, oruc tarixləri) öyrənin və komandanıza mövcud yerləşdirmə variantlarını proaktiv şəkildə bildirin.'
) ON CONFLICT (id) DO NOTHING;

-- Q4: MCQ — Medium — Emotional support boundaries
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000004',
    '88888888-8888-8888-8888-888888888888',
    'medium', 'mcq',
    'An attendee begins sharing deeply personal and emotional problems with you during the event. They seem to need significant emotional support. How do you handle this?',
    'Bir iştirakçı tədbir zamanı sizinlə çox şəxsi və emosional problemlərini bölüşməyə başlayır. Onlar ciddi emosional dəstəyə ehtiyac duyurlar. Bunu necə idarə edirsiniz?',
    '[
        {"key": "A", "text_en": "Listen for as long as they need — supporting people is the most important thing", "text_az": "Ehtiyac duyduqları qədər dinlə — insanlara dəstək olmaq ən vacib şeydir"},
        {"key": "B", "text_en": "Listen briefly with empathy, acknowledge their feelings, then gently explain your role limits and guide them toward appropriate support (event counsellor, helpline)", "text_az": "Empatiya ilə qısa dinlə, hisslərini tanı, sonra nəzakətlə rolunuzun məhdudiyyətlərini izah edin və uyğun dəstəyə (məsləhətçi, köməkxətt) yönləndir"},
        {"key": "C", "text_en": "Politely excuse yourself immediately — this is not your job", "text_az": "Dərhal nəzakətlə özünüzü bağışlayın — bu sizin işiniz deyil"},
        {"key": "D", "text_en": "Give them your personal phone number so they can call you after the event", "text_az": "Şəxsi telefon nömrənizi verin ki, tədbirden sonra sizə zəng edə bilsinlər"}
    ]',
    'B',
    1.9, 0.3, 0.10,
    'Empathy has professional boundaries. A brief, compassionate acknowledgment followed by referral to appropriate support respects both the person and your role. Personal contact sharing creates unhealthy dependency.',
    'Empatinin peşəkar hüdudları var. Qısa, mərhəmətli tanınmanın ardından uyğun dəstəyə yönləndirilmə həm insana, həm də rolunuza hörmət edir. Şəxsi əlaqəni paylaşmaq sağlıksız asılılıq yaradır.',
    'Learn the phrase: ''I hear you and what you are sharing matters. I want to connect you with someone who can really help.'' Practice delivering it warmly and confidently.',
    'Cümləni öyrənin: ''Sizi eşidirəm və paylaşdığınız şey vacibdir. Sizi həqiqətən kömək edə biləcək biriylə əlaqəlqandırmaq istəyirəm.'' Onu isti və inamlı şəkildə çatdırmağı məşq edin.'
) ON CONFLICT (id) DO NOTHING;

-- Q5: MCQ — Medium — Safeguarding disclosure
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000005',
    '88888888-8888-8888-8888-888888888888',
    'medium', 'mcq',
    'A youth participant (age 16) quietly tells you they feel unsafe because an adult at the event has been making them uncomfortable with repeated unwanted physical contact. What do you do?',
    'Bir gənc iştirakçı (16 yaş) sakit şəkildə sizə tədbirde bir böyüyün təkrar edilən istənilməyən fiziki təmasla onları narahat etdiyindən özünü təhlükəsiz hiss etmədiyini söyləyir. Nə edirsiniz?',
    '[
        {"key": "A", "text_en": "Tell them to avoid that person for the rest of the event", "text_az": "Onlara tədbirlerin qalan hissəsindəki bu şəxsdən uzaq durmalarını söylə"},
        {"key": "B", "text_en": "Believe them, thank them for telling you, ensure their immediate safety, report to the designated safeguarding officer immediately without delay, and do not promise confidentiality", "text_az": "İnan, söylədiyi üçün təşəkkür et, dərhal təhlükəsizliyini təmin et, gizlilik vəd etmədən dərhal təyin edilmiş qoruma məmuruna bildir"},
        {"key": "C", "text_en": "Investigate by approaching the accused adult yourself first", "text_az": "Əvvəlcə özün ittiham olunan böyüyə yaxınlaşaraq araşdır"},
        {"key": "D", "text_en": "Tell them you will look into it after the event finishes", "text_az": "Tədbir bitdikten sonra araşdıracağını söylə"}
    ]',
    'B',
    2.3, 0.6, 0.05,
    'Safeguarding disclosures require: believe the person, ensure immediate safety, report to the designated safeguarding officer immediately, do not investigate yourself, and never promise confidentiality as disclosure may be required.',
    'Qoruma açıqlamaları tələb edir: insana inan, dərhal təhlükəsizliyini təmin et, dərhal təyin edilmiş qoruma məmuruna bildir, özün araşdırma, açıqlama tələb oluna biləcəyi üçün heç vaxt məxfilik vəd etmə.',
    'Every volunteer working with youth must know: (1) your org''s designated safeguarding officer, (2) the 4 types of abuse, (3) the exact reporting steps. This is non-negotiable knowledge.',
    'Gəncliklə işləyən hər könüllü bilməlidir: (1) təşkilatınızın təyin edilmiş qoruma məmuru, (2) istismarın 4 növü, (3) dəqiq hesabat addımları. Bu danışılmaz bilikdir.'
) ON CONFLICT (id) DO NOTHING;

-- Q6: MCQ — Medium — Handling aggressive behavior empathetically
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    options, correct_answer,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000006',
    '88888888-8888-8888-8888-888888888888',
    'medium', 'mcq',
    'An elderly attendee becomes increasingly angry at the registration desk because they cannot find their name on the list. They begin raising their voice. What is the most empathetic and effective response?',
    'Yaşlı bir iştirakçı qeydiyyat masasında adını siyahıda tapa bilmədiyindən getdikcə əsəbiləşir. Səsini qaldırmağa başlayır. Ən empatik və effektiv cavab nədir?',
    '[
        {"key": "A", "text_en": "Match their energy and speak loudly and firmly back", "text_az": "Enerjilərinə uyğun şəkildə möhkəm və ucadan cavab ver"},
        {"key": "B", "text_en": "Acknowledge their frustration, lower your own voice deliberately, affirm you will resolve it, then search the system and offer a manual entry workaround if needed", "text_az": "Məyusluqlarını qəbul et, öz səsini qəsdən alçalt, həll edəcəyini təsdiqlə, sistemi axtar və lazım olursa manual giriş alternativini təklif et"},
        {"key": "C", "text_en": "Call security immediately to manage the situation", "text_az": "Vəziyyəti idarə etmək üçün dərhal təhlükəsizliyi çağır"},
        {"key": "D", "text_en": "Tell them to calm down before you can help them", "text_az": "Kömək edə bilməzdən əvvəl sakinləşmələrini söylə"}
    ]',
    'B',
    2.0, 0.4, 0.08,
    'Deliberate calm voice is a proven de-escalation tool. Acknowledging frustration before problem-solving validates the person. Demanding they calm down first escalates aggression — it reverses the emotional contract.',
    'Qəsdli sakit səs sübut edilmiş sakinləşdirmə vasitəsidir. Problem həll etməzdən əvvəl məyusluğu qəbul etmək insanı doğrulayır. Əvvəlcə sakinləşmələrini tələb etmək aqressivliyi artırır.',
    'Practice deliberate voice modulation: when someone raises their voice, consciously lower yours by 30%. This technique works in 85% of conflict situations.',
    'Qəsdli səs modulyasiyasını məşq edin: kimsə səsini qaldıranda, özünkünü 30% aşağı salın. Bu texnika münaqişə vəziyyətlərinin 85%-ında işləyir.'
) ON CONFLICT (id) DO NOTHING;

-- Q7: Open-ended — Hard — Supporting a participant with a mental health episode
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000007',
    '88888888-8888-8888-8888-888888888888',
    'hard', 'open_ended',
    'During a high-pressure closing ceremony a participant begins hyperventilating and crying uncontrollably. They are in a crowded room and people are starting to stare. Describe your full response.',
    'Gərgin bir bağlanış seremoniyası zamanı bir iştirakçı hiperventilasiya edir və nəzarətsiz ağlamağa başlayır. Onlar izdihamlı bir otaqdadır və insanlar baxmağa başlayır. Tam cavabınızı izah edin.',
    '[
        {"name": "immediate_calm_presence", "weight": 0.20, "keywords": ["calm", "kneel", "ground level", "speak softly", "safe", "sakit", "çök", "yerdə", "yavaş danış", "təhlükəsiz"]},
        {"name": "privacy_protection", "weight": 0.25, "keywords": ["crowd", "move away", "private", "screen", "reduce audience", "izdiham", "kənara çək", "özəl", "ekran", "tamaşaçıları azalt"]},
        {"name": "grounding_technique", "weight": 0.20, "keywords": ["breathe", "focus", "5 things", "ground", "nəfəs", "diqqət", "5 şey", "yer tutma", "real"]},
        {"name": "professional_escalation", "weight": 0.20, "keywords": ["medical", "first aid", "coordinator", "escalate", "tibbi", "ilk yardım", "koordinator", "yüksəlt"]},
        {"name": "dignity_preservation", "weight": 0.15, "keywords": ["dignity", "no photos", "respect", "privacy", "ləyaqət", "foto yox", "hörmət", "məxfilik"]}
    ]',
    2.4, 1.0, 0.0,
    'Managing a mental health episode in public requires: immediate calm presence, removing the person from public view, grounding techniques, timely escalation to medical/first aid, and strict dignity protection.',
    'İctimai yerdəki psixi sağlamlıq epizodunu idarə etmək tələb edir: dərhal sakit mövcudluq, şəxsi ictimai görüşdən kənara çıxarma, yer tutma texnikaları, tibbi/ilk yardıma vaxtlı eskalasiya, ciddi ləyaqət qoruması.',
    'Learn the 5-4-3-2-1 grounding technique: name 5 things you see, 4 things you can touch, 3 things you hear, 2 things you smell, 1 thing you taste. Practice it so you can guide someone through it calmly.',
    '5-4-3-2-1 yer tutma texnikasını öyrənin: 5 gördüyünüz şeyi, 4 toxuna biləcəyinizi, 3 eşitdiyinizi, 2 iylədiğinizi, 1 dadını bilin. Birini sakinliklə istiqamətləndirə biləcək şəkildə məşq edin.'
) ON CONFLICT (id) DO NOTHING;

-- Q8: Open-ended — Hard — Cultural sensitivity in a multi-national delegation
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000008',
    '88888888-8888-8888-8888-888888888888',
    'hard', 'open_ended',
    'You are hosting a networking dinner for 60 delegates from 15 countries. You notice tension at one table where a delegate from one culture is being repeatedly interrupted by another, who does not realize their communication style is seen as rude. How do you navigate this without embarrassing anyone?',
    'Siz 15 ölkədən 60 nümayəndə üçün networking şam yeməyinə ev sahibliyi edirsiniz. Bir masada bir mədəniyyətin nümayəndəsinin başqa biri tərəfindən dəfələrlə kəsildiyini fərk edirsiniz, ikincisi ünsiyyət tərzinin kobudluq kimi qəbul edildiyini başa düşmür. Heç kimi utandırmadan bunu necə idarə edirsiniz?',
    '[
        {"name": "private_gentle_intervention", "weight": 0.30, "keywords": ["private", "side", "quietly", "individual", "özəl", "yanına", "sakit", "fərdi", "bir tərəfə çək"]},
        {"name": "cultural_framing", "weight": 0.25, "keywords": ["different styles", "cultural difference", "not personal", "context", "fərqli üslublar", "mədəni fərq", "şəxsi deyil", "kontekst"]},
        {"name": "redirect_conversation", "weight": 0.20, "keywords": ["redirect", "change topic", "new question", "break", "yönləndir", "mövzunu dəyiş", "yeni sual", "fasilə"]},
        {"name": "check_in_with_affected", "weight": 0.25, "keywords": ["check in", "how are you", "ask", "listen", "yoxla", "necəsiniz", "soruş", "dinlə"]}
    ]',
    2.3, 1.1, 0.0,
    'Cultural diplomacy requires indirect, private interventions that frame behavior as cultural rather than personal, combined with proactive check-ins with the person affected.',
    'Mədəni diplomatiya davranışı şəxsi deyil mədəni olaraq çərçivəleyən dolayı, özəl müdaxilələri, zərər görən şəxslə proaktiv yoxlamalar ilə birləşdirməyi tələb edir.',
    'Study the Hofstede model: Power Distance, Individualism, Uncertainty Avoidance. Understanding these 3 dimensions explains 70% of cross-cultural friction at international events.',
    'Hofstede modelini öyrənin: Güc məsafəsi, Fərdilik, Qeyri-müəyyənlikdən qaçmaq. Bu 3 ölçünü anlamaq beynəlxalq tədbirlərdəki mədəniyyətlərarası sürtüşmənin 70%-ni izah edir.'
) ON CONFLICT (id) DO NOTHING;

-- Q9: Open-ended — Medium — Inclusive access for a delegate with a disability
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000009',
    '88888888-8888-8888-8888-888888888888',
    'medium', 'open_ended',
    'A delegate arrives in a wheelchair and the entrance ramp to the main hall is blocked by equipment that was set up for a photo call. The event is starting in 15 minutes. Describe exactly what you do.',
    'Bir nümayəndə təkərli kresloda gəlir və əsas salona aparan rampa foto çəkiliş üçün qurulmuş avadanlıq ilə bağlanıb. Tədbir 15 dəqiqəyə başlayır. Dəqiq nə edəcəyinizi izah edin.',
    '[
        {"name": "immediate_removal", "weight": 0.30, "keywords": ["clear", "move equipment", "unblock", "remove", "temizlə", "avadanlığı köçür", "aç", "götür"]},
        {"name": "alternative_access", "weight": 0.25, "keywords": ["alternative route", "other entrance", "accessible path", "alternative giriş", "başqa giriş", "əlçatan yol"]},
        {"name": "personal_escort", "weight": 0.20, "keywords": ["escort", "accompany", "stay with", "guide", "müşayiət", "birgə", "yanında qal", "rəhbərlik"]},
        {"name": "prevent_recurrence", "weight": 0.25, "keywords": ["report", "flag", "coordinator", "photo call moved", "never block", "bildir", "koordinator", "foto yeri", "bir daha blok etmə"]}
    ]',
    1.9, 0.3, 0.0,
    'Accessibility is non-negotiable. The first response is always to remove the barrier or find an accessible route immediately — not to ask the delegate to wait. Then escalate to prevent it happening again.',
    'Əlçatanlıq danışıqsızdır. İlk cavab həmişə maneəni dərhal aradan qaldırmaq və ya əlçatan marşrut tapmaqdir — nümayəndədən gözləməsini xahiş etmək deyil. Sonra bir daha baş verməsinin qarşısını almaq üçün eskalasiya edin.',
    'At event setup: always walk the access routes in the role of a wheelchair user before doors open. This one habit prevents 90% of accessibility failures.',
    'Tədbir qurulmasında: qapılar açılmadan əvvəl həmişə təkərli kreslolu bir istifadəçinin rolunda giriş marşrutlarını keçin. Bu bir vərdiş əlçatanlıq uğursuzluqlarının 90%-nin qarşısını alır.'
) ON CONFLICT (id) DO NOTHING;

-- Q10: Open-ended — Hard — Volunteer team member showing signs of burnout
INSERT INTO public.questions (
    id, competency_id, difficulty, type,
    scenario_en, scenario_az,
    expected_concepts,
    irt_a, irt_b, irt_c,
    feedback_en, feedback_az,
    development_tip_en, development_tip_az
) VALUES (
    '80000001-0000-0000-0000-000000000010',
    '88888888-8888-8888-8888-888888888888',
    'hard', 'open_ended',
    'You notice that a fellow volunteer who has been working every day for 5 days straight is becoming withdrawn, snapping at attendees, and making small errors they normally would not make. They have not said anything to you. What do you do?',
    'Beş gündür fasiləsiz işləyən bir həmkar könüllünün içinə çəkildiğini, iştirakçılara hücum etdiyini və adətən etməyəcəyi kiçik səhvlər etdiyini fərk edirsiniz. Sizinlə heç nə paylaşmayıblar. Nə edirsiniz?',
    '[
        {"name": "private_check_in", "weight": 0.25, "keywords": ["private", "quiet moment", "check in", "ask how they are", "özəl", "sakit an", "yoxla", "necəsiniz soruş"]},
        {"name": "non_judgmental_observation", "weight": 0.25, "keywords": ["noticed", "observed", "no blame", "concerned", "fərq etdim", "müşahidə", "ittiham yox", "narahat oldum"]},
        {"name": "offer_practical_help", "weight": 0.20, "keywords": ["cover", "break", "rest", "take over", "əvəz", "fasilə", "istirahət", "üstlən"]},
        {"name": "escalate_if_needed", "weight": 0.15, "keywords": ["coordinator", "escalate", "report welfare concern", "koordinator", "yüksəlt", "rifahı bildir"]},
        {"name": "follow_up", "weight": 0.15, "keywords": ["check back", "follow up", "next day", "continue support", "yenidən yoxla", "izlə", "növbəti gün", "dəstəyə davam"]}
    ]',
    2.2, 0.9, 0.0,
    'Peer empathy in volunteering includes recognizing unspoken distress, making private non-judgmental check-ins, offering practical relief, knowing when to involve a coordinator, and following up.',
    'Könüllülükdə həmyaşıd empatiyası deyilməmiş narahatlığı tanımağı, özəl qeyri-mühakimə yoxlamalarını, praktik kömək təklif etməyi, koordinatoru nə vaxt cəlb etməyi bilməyi, izləməyi əhatə edir.',
    'Learn the ALGEE mental health first aid framework: Approach, Listen, Give support, Encourage professional help, Encourage self-help. This applies to both event participants and fellow volunteers.',
    'ALGEE psixi sağlamlıq ilk yardım çərçivəsini öyrənin: Yaxınlaş, Dinlə, Dəstək ver, Peşəkar kömək almağa həvəsləndir, Öz-özünə kömək almağa həvəsləndir. Bu həm tədbir iştirakçılarına, həm də həmkar könüllülərə tətbiq olunur.'
) ON CONFLICT (id) DO NOTHING;
-- =============================================================================
-- RELIABILITY COMPETENCY (10 questions)
-- competency_id: 22222222-2222-2222-2222-222222222222
-- =============================================================================

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000001', '22222222-2222-2222-2222-222222222222', 'easy', 'mcq', 'You signed up to volunteer at a cultural festival registration desk from 8am to 2pm. On the morning of the event, you wake up feeling slightly tired but not ill. What do you do?', 'Siz bir mədəniyyət festivalının qeydiyyat masasında saat 08:00-dan 14:00-a kimi könüllü olmağa qeydiyyatdan keçmisiniz. Tədbir günü səhər bir az yorğun oyanırsınız, lakin xəstə deyilsiniz. Nə edirsiniz?', '[{"key":"A","text_en":"Call the coordinator and say you cannot make it","text_az":"Koordinatora zəng edib gələ bilməyəcəyinizi bildirirsiniz"},{"key":"B","text_en":"Show up on time as committed and fulfill your shift","text_az":"Öhdəliyinizə uyğun olaraq vaxtında gəlib növbənizi yerinə yetirirsiniz"},{"key":"C","text_en":"Arrive an hour late hoping no one notices","text_az":"Heç kimin fərq etməyəcəyini ümid edərək bir saat gecikərək gəlirsiniz"},{"key":"D","text_en":"Ask a friend to cover without informing the coordinator","text_az":"Koordinatoru xəbərdar etmədən bir dostunuzdan sizi əvəz etməsini xahiş edirsiniz"}]'::jsonb, 'B', NULL, 1.2, -1.2, 0.15, 'Reliability means honoring your commitments even when it is inconvenient.', 'Etibarlılıq, narahat olsa belə öhdəliklərinizə sadiq qalmaq deməkdir.', 'Build a pre-event routine: prepare transport and clothes the night before.', 'Tədbirdən əvvəlki bir rutin qurun: nəqliyyat və geyiminizi bir gecə əvvəl hazırlayın.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000002', '22222222-2222-2222-2222-222222222222', 'easy', 'mcq', 'Your volunteer team lead asked you to submit your availability form by Friday. It is Thursday evening and you have not filled it out yet. What is the most responsible action?', 'Könüllü komanda lideriniz sizdən cümə gününə qədər mövcudluq formanızı təqdim etməyinizi istədi. İndi cümə axşamı axşamıdır. Ən məsuliyyətli hərəkət nədir?', '[{"key":"A","text_en":"Fill it out immediately and submit tonight","text_az":"Formanı dərhal doldurun və bu gecə göndərin"},{"key":"B","text_en":"Wait until Friday morning since there is still time","text_az":"Hələ vaxt olduğu üçün cümə səhərinə qədər gözləyin"},{"key":"C","text_en":"Ignore it — the team lead will remind you","text_az":"Laqeyd yanaşın — komanda lideri sizi yenidən xatırladacaq"},{"key":"D","text_en":"Ask a teammate to submit on your behalf","text_az":"Bir komanda yoldaşınızdan sizin adınıza göndərməsini xahiş edin"}]'::jsonb, 'A', NULL, 1.1, -1.4, 0.15, 'Completing tasks before the deadline demonstrates proactive reliability.', 'Tapşırıqları son tarixdən əvvəl tamamlamaq fəal etibarlılığı nümayiş etdirir.', 'Use a phone reminder as soon as you receive any task.', 'Hər hansı bir tapşırıq aldığınız anda telefon xatırlatması istifadə edin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000003', '22222222-2222-2222-2222-222222222222', 'easy', 'open_ended', 'Describe a time when you committed to doing something and then had to decide whether to follow through despite an obstacle. What did you do and why?', 'Bir şeyə öhdəlik götürdüyünüz, lakin sonradan bir maneəyə baxmayaraq onu yerinə yetirməli olub-olmadığınıza qərar verməli olduğunuz bir vəziyyəti təsvir edin.', NULL, NULL, '[{"name":"follow_through","weight":0.40,"keywords":["followed through","kept my promise","showed up","completed"]},{"name":"obstacle_acknowledgment","weight":0.30,"keywords":["despite","obstacle","challenge","difficult","problem"]},{"name":"communication","weight":0.30,"keywords":["told","informed","communicated","notified"]}]'::jsonb, 1.0, -1.0, 0.0, 'Strong answers include acknowledging the obstacle honestly and explaining the decision to follow through.', 'Güclü cavablar maneəni dürüstcəsinə etiraf etməyi və davam etmək qərarını izah etməyi əhatə edir.', 'Keep a personal log of commitments you make.', 'Götürdüyünüz öhdəliklərin şəxsi qeydini saxlayın.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000004', '22222222-2222-2222-2222-222222222222', 'medium', 'mcq', 'You are coordinating 8 volunteers at an international sports event. Two volunteers text you 90 minutes before their shift saying they cannot come. You have no replacement list. What is your first action?', 'Beynəlxalq bir idman tədbirində 8 könüllüdən ibarət qrupu koordinasiya edirsiniz. İki könüllü növbələrindən 90 dəqiqə əvvəl gələ bilməyəcəklərini bildirir. Əvəzetmə siyahınız yoxdur. İlk hərəkətiniz nədir?', '[{"key":"A","text_en":"Inform your supervisor immediately and propose redistributing tasks among the remaining 6","text_az":"Dərhal rəhbərinizi məlumatlandırın və tapşırıqları qalan 6 nəfər arasında bölüşdürməyi təklif edin"},{"key":"B","text_en":"Wait to see if they change their minds","text_az":"Fikirlarini dəyişib-dəyişməyəcəklərini gözləyin"},{"key":"C","text_en":"Handle everything yourself","text_az":"Hər şeyi özünüz həll edin"},{"key":"D","text_en":"Post on social media asking for volunteers","text_az":"Sosial mediada könüllü axtarışı paylaşın"}]'::jsonb, 'A', NULL, 1.5, -0.2, 0.12, 'Reliable coordinators escalate problems early while proposing solutions.', 'Etibarlı koordinatorlar problemləri erkən bildirərkən həll yolları təklif edirlər.', 'Build a short-notice replacement contact list before every event.', 'Hər tədbirden əvvəl qısa bildiriş üçün əvəzetmə əlaqə siyahısı hazırlayın.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000005', '22222222-2222-2222-2222-222222222222', 'medium', 'mcq', 'You promised to deliver a translated welcome packet by Monday. You finish Sunday night but realize a section has errors. Fixing it will take 2 more hours. What do you do?', 'Bazar ertəsi gününə qədər tərcümə edilmiş qarşılama paketini təhvil verməyi vəd etdiniz. Bazar günü gecəsi bir bölmədə xəta olduğunu anlayırsınız. Düzəltmək 2 saat aparacaq. Nə edirsiniz?', '[{"key":"A","text_en":"Submit it as-is to meet the deadline","text_az":"Son tarixə çatmaq üçün olduğu kimi göndərin"},{"key":"B","text_en":"Stay up and fix the errors on time","text_az":"Yuxu qurbanı verin, xətaları düzəldin"},{"key":"C","text_en":"Notify your coordinator tonight and propose a revised deadline","text_az":"Bu gecə koordinatorunuza məlumat verin və yenidən baxılmış son tarix təklif edin"},{"key":"D","text_en":"Skip the correction — delegates rarely read them carefully","text_az":"Düzəlişdən imtina edin — nümayəndələr nadir hallarda diqqətlə oxuyur"}]'::jsonb, 'C', NULL, 1.6, 0.1, 0.10, 'Proactive communication with a solution preserves trust more than delivering flawed work.', 'Həll yolu ilə fəal ünsiyyət qüsurlu iş təhvil verməkdən daha çox etibarı qoruyur.', 'Always build a 2-hour buffer into any document deadline.', 'Hər sənəd son tarixi üçün həmişə 2 saatlıq ehtiyat nəzərdə tutun.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000006', '22222222-2222-2222-2222-222222222222', 'medium', 'open_ended', 'You are managing a task with a deadline during a multi-day event. Halfway through, you realize you will not finish on time. Walk through how you would handle this.', 'Çoxgünlük tədbiirdə son tarixi olan tapşırığı idarə edirsiniz. Ortada vaxtında bitirə bilməyəcəyinizi başa düşürsünüz. Bu vəziyyəti necə həll edərdiniz?', NULL, NULL, '[{"name":"early_escalation","weight":0.35,"keywords":["immediately","as soon as","notified","informed","flagged"]},{"name":"solution_proposal","weight":0.35,"keywords":["proposed","suggested","alternative","extend","reprioritize","delegate"]},{"name":"transparency","weight":0.30,"keywords":["honest","transparent","explained","communicated","updated"]}]'::jsonb, 1.4, 0.0, 0.0, 'Best answers show early escalation, a concrete solution, and transparent communication.', 'Ən yaxşı cavablar erkən eskalasiya, konkret həll yolu və şəffaf ünsiyyəti göstərir.', 'Practice: "I want to flag an issue early so we can solve it together."', '"Birlikdə həll edə bilməmiz üçün bir problemi erkən qeyd etmək istəyirəm" deməyi məşq edin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000007', '22222222-2222-2222-2222-222222222222', 'medium', 'mcq', 'A supervisor assigns you a task with no specific deadline, saying "get it done when you can." Three days pass. What do you do?', 'Rəhbər sizə konkret son tarix olmadan tapşırıq verir. Üç gün keçir. Nə edirsiniz?', '[{"key":"A","text_en":"Wait until someone asks about it","text_az":"Biri soruşana qədər gözləyin"},{"key":"B","text_en":"Set your own internal deadline, complete the task, and proactively update your supervisor","text_az":"Öz daxili son tarixi müəyyənləşdirin, tamamlayın və rəhbərinizi məlumatlandırın"},{"key":"C","text_en":"Ask your supervisor for a deadline before starting","text_az":"Başlamazdan əvvəl rəhbərinizdən son tarix istəyin"},{"key":"D","text_en":"Do a partial version and report it as complete","text_az":"Qismən hazırlayın və tamamlanmış kimi bildirin"}]'::jsonb, 'B', NULL, 1.4, 0.2, 0.12, 'Reliable volunteers do not need external pressure to perform.', 'Etibarlı könüllülər performans üçün xarici təzyiqə ehtiyac duymur.', 'For any open-ended task, immediately set a personal deadline earlier than needed.', 'Açıq tapşırıq üçün dərhal lazım olandan daha erkən şəxsi son tarix müəyyənləşdirin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000008', '22222222-2222-2222-2222-222222222222', 'hard', 'mcq', 'You have been consistently reliable for 6 months. Your coordinator now assigns you significantly more tasks than others, assuming you will handle it. You are approaching burnout. What is the most professionally reliable response?', 'Siz 6 ay ardıcıl etibarlı olmusunuz. Koordinator indi sizə digərlərindən çox tapşırıq verir. Tükənmə həddinə yaxınlaşırsınız. Ən peşəkar cavab nədir?', '[{"key":"A","text_en":"Accept all tasks silently to protect your reputation","text_az":"Reputasiyanızı qorumaq üçün bütün tapşırıqları səssizcə qəbul edin"},{"key":"B","text_en":"Decline everything suddenly","text_az":"Birdən hər şeyi rədd edin"},{"key":"C","text_en":"Have an honest conversation about capacity and propose a sustainable workload","text_az":"İmkanlarınız haqqında dürüst söhbət edin və davamlı iş yükü təklif edin"},{"key":"D","text_en":"Start missing deadlines so the coordinator reduces your load","text_az":"Son tarixləri qaçırmağa başlayın"}]'::jsonb, 'C', NULL, 2.0, 1.0, 0.10, 'True reliability is sustainable. A proactive capacity conversation preserves both quality and the relationship.', 'Həqiqi etibarlılıq davamlıdır. Fəal imkan söhbəti həm keyfiyyəti, həm də münasibəti qoruyur.', 'Learn to say: "I want to stay reliable for you, so I need to flag that I am at capacity."', '"Sizin üçün etibarlı qalmaq istəyirəm, imkan həddimə çatdığımı qeyd etməliyəm" deməyi öyrənin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000009', '22222222-2222-2222-2222-222222222222', 'hard', 'open_ended', 'You are the lead volunteer for an accreditation desk at a major summit. Two hours before opening, the badge-printing system is down and your technical contact is unreachable. 300 delegates expected. Describe your full response plan.', 'Sammitdə akkreditasiya masasının aparıcı könüllüsüsünüz. Açılışdan iki saat əvvəl nişan çap sistemi işləmir və texniki əlaqə şəxsinizə çata bilmirsiniz. 300 nümayəndə gözlənilir. Tam cavab planınızı təsvir edin.', NULL, NULL, '[{"name":"immediate_action","weight":0.30,"keywords":["backup","manual","alternative","workaround","hand-written"]},{"name":"escalation_chain","weight":0.35,"keywords":["supervisor","manager","informed","escalated","reported"]},{"name":"stakeholder_communication","weight":0.20,"keywords":["delegates","informed","signage","announcement"]},{"name":"calm_leadership","weight":0.15,"keywords":["calm","organized","assigned","coordinated","delegated"]}]'::jsonb, 2.2, 1.4, 0.0, 'Top answers include: concrete workaround, rapid escalation, proactive delegate communication, and calm leadership.', 'Ən yaxşı cavablara daxildir: konkret həll, sürətli eskalasiya, fəal nümayəndə ünsiyyəti və sakit rəhbərlik.', 'Study incident command structure: communication, workaround, and messaging as three separate roles.', 'Hadisə komandanlıq strukturunu öyrənin: ünsiyyət, həll yolu və mesajlaşma üç ayrı rol kimi.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('20000001-0000-0000-0000-000000000010', '22222222-2222-2222-2222-222222222222', 'hard', 'open_ended', 'Over three months you have missed two deadlines, been late to one shift, and forgotten to send one report. Your coordinator has not confronted you yet. What do you do, and how do you rebuild your reliability record?', 'Son üç ayda iki son tarixi qaçırmısınız, bir növbəyə gecikmisiniz və bir hesabat göndərməyi unutmusunuz. Koordinatorunuz hələ müraciət etməyib. Nə edirsiniz?', NULL, NULL, '[{"name":"self_accountability","weight":0.35,"keywords":["acknowledged","took responsibility","admitted","my fault"]},{"name":"proactive_disclosure","weight":0.30,"keywords":["went to coordinator","proactively","without being asked","told them first"]},{"name":"concrete_improvement_plan","weight":0.35,"keywords":["calendar","reminder","system","checklist","habit","process change"]}]'::jsonb, 2.0, 1.2, 0.0, 'Highest-scoring answers go to the coordinator proactively and present a concrete system change, not just a promise.', 'Ən yüksək bal toplayan cavablar koordinatora fəal gedir və yalnız vəd deyil, konkret sistem dəyişikliyi təqdim edir.', 'After any failure, do a 5-minute root cause analysis: planning, motivation, or system failure? Fix the system.', 'Hər uğursuzluqdan sonra 5 dəqiqəlik kök səbəb analizi edin: planlaşdırma, motivasiya, yoxsa sistem? Sistemi düzəldin.') ON CONFLICT (id) DO NOTHING;

-- =============================================================================
-- ENGLISH PROFICIENCY COMPETENCY (10 questions)
-- competency_id: 33333333-3333-3333-3333-333333333333
-- =============================================================================

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000001', '33333333-3333-3333-3333-333333333333', 'easy', 'mcq', 'A delegate asks: "Where is the registration desk?" Which response is most appropriate?', 'Nümayəndə soruşur: "Qeydiyyat masası haradadır?" Hansı cavab ən uyğundur?', '[{"key":"A","text_en":"Point silently","text_az":"Səssizcə işarə edin"},{"key":"B","text_en":"The registration desk is just around the corner to your left — I can walk you there if you like.","text_az":"Qeydiyyat masası sol tərəfdə küncdədir — istəsəniz sizi ora apara bilərəm."},{"key":"C","text_en":"One moment please — let me find someone who speaks better English","text_az":"Bir dəqiqə — ingilis dili daha yaxşı olan birini tapım"},{"key":"D","text_en":"Registration? Yes, there — while pointing vaguely","text_az":"Qeydiyyat? Bəli, orada — qeyri-müəyyən işarə edərək"}]'::jsonb, 'B', NULL, 1.2, -1.3, 0.15, 'Option B provides a complete, helpful answer in clear English and offers additional assistance.', 'B seçimi aydın ingilis dilində tam cavab verir və əlavə yardım təklif edir.', 'Practice giving directions using landmarks: turn left at the blue banner.', 'İstiqamət verməyi məşq edin: mavi lövhənin yanında sola dönün.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000002', '33333333-3333-3333-3333-333333333333', 'easy', 'mcq', 'A participant hands you a form and says "I am not sure I filled this correctly." What is the best response?', 'İştirakçı sizə forma uzadır: "Düzgün doldurmağımdan əmin deyiləm." Ən yaxşı cavab nədir?', '[{"key":"A","text_en":"Take the form and fill it out for them without explaining","text_az":"Formanı götürün və izah etmədən doldurun"},{"key":"B","text_en":"Say dont worry and submit it as-is","text_az":"Narahat olmayın deyərək olduğu kimi təqdim edin"},{"key":"C","text_en":"Review the form together and explain what is needed in simple English","text_az":"Formanı birlikdə nəzərdən keçirin və sadə ingilis dilindəki tələbləri izah edin"},{"key":"D","text_en":"Tell them to go to the main information desk","text_az":"Onlara əsas məlumat masasına getmələrini söyləyin"}]'::jsonb, 'C', NULL, 1.1, -1.1, 0.15, 'Option C shows helpfulness while building understanding through simple English.', 'C seçimi sadə ingilis dilindəki birlikdə nəzərdən keçirmə ilə köməkçiliyi göstərir.', 'Learn phrases for form assistance: This field needs your full name.', 'Form köməyi üçün ifadələr öyrənin: Bu xana tam adınızı tələb edir.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000003', '33333333-3333-3333-3333-333333333333', 'easy', 'open_ended', 'A delegate asks: "What is the schedule for tomorrow''s sessions?" Write exactly what you would say in English.', 'Nümayəndə soruşur: "Sabahkı sessiyaların proqramı nədir?" İngilis dilində nə deyəcəyinizi yazın.', NULL, NULL, '[{"name":"clear_english","weight":0.40,"keywords":["tomorrow","sessions","schedule","starts","begins","morning","time"]},{"name":"helpfulness","weight":0.35,"keywords":["let me check","I can show you","here is","happy to help"]},{"name":"politeness","weight":0.25,"keywords":["sure","of course","certainly","please","thank you"]}]'::jsonb, 1.0, -1.2, 0.0, 'Strong answers provide a natural English response with actual schedule info or offer to find it.', 'Güclü cavablar faktiki cədvəl məzmunu olan təbii ingilis cavabı verir.', 'Memorize a schedule request script for common event types.', 'Ümumi tədbir növləri üçün cədvəl sorğusu skripti əzbərləyin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000004', '33333333-3333-3333-3333-333333333333', 'medium', 'mcq', 'You need to relay: "The afternoon session moved from Room 3 to the Main Hall." A delegate says "Could you say that again more slowly?" What do you do?', 'Mesaj ötürməlisiniz: "Günortadan sonrakı sessiya 3-cü otaqdan Əsas Salona köçürülüb." Nümayəndə deyir: "Daha yavaş təkrarlaya bilərsinizmi?"', '[{"key":"A","text_en":"Repeat the exact same sentence at the same speed","text_az":"Eyni cümləni eyni sürətlə təkrarlayın"},{"key":"B","text_en":"Repeat slowly, breaking it into two parts: location change first, then the reason","text_az":"Yavaş-yavaş təkrarlayın və iki hissəyə bölün"},{"key":"C","text_en":"Hand them a written note instead","text_az":"Bunun əvəzinə yazılı qeyd verin"},{"key":"D","text_en":"Ask a louder colleague to deliver it","text_az":"Daha ucadan danışan həmkardan xahiş edin"}]'::jsonb, 'B', NULL, 1.6, 0.0, 0.12, 'Breaking messages into logical chunks and slowing down is the correct adaptive technique.', 'Mesajı məntiqi parçalara bölmək və yavaşlamaq düzgün uyğunlaşdırma texnikasıdır.', 'Practice chunk-and-pause: one piece of info, 2-second pause, then next piece.', 'Parça-və-fasilə məşq edin: bir məlumat, 2 saniyə fasilə, sonra növbəti.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000005', '33333333-3333-3333-3333-333333333333', 'medium', 'mcq', 'A journalist asks: "Can you explain the main goal of this event?" You know the answer but are unsure about some vocabulary. Best approach?', 'Jurnalist soruşur: "Bu tədbirinin əsas məqsədini izah edə bilərsinizmi?" Cavabı bilirsiniz, lakin bəzi sözlərdən əmin deyilsiniz.', '[{"key":"A","text_en":"Decline and direct them to the spokesperson","text_az":"İmtina edin və sözcüyə yönləndirin"},{"key":"B","text_en":"Answer using simple, clear words you are confident about","text_az":"Əmin olduğunuz sadə, aydın sözlərlə cavab verin"},{"key":"C","text_en":"Give a very long answer to show vocabulary range","text_az":"Lüğət nümayiş etdirmək üçün uzun cavab verin"},{"key":"D","text_en":"Answer in Azerbaijani and ask them to use Google Translate","text_az":"Azərbaycan dilində cavab verin"}]'::jsonb, 'B', NULL, 1.5, 0.1, 0.10, 'Confident, simple English is always more effective than complex vocabulary delivered uncertainly.', 'Əmin, sadə ingilis dili qeyri-əmin mürəkkəb lüğətdən daha effektivdir.', 'Build a 20-30 term event vocabulary bank and review before each event.', 'Hər tədbir üçün 20-30 terminlik lüğət bankı qurun.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000006', '33333333-3333-3333-3333-333333333333', 'medium', 'open_ended', 'A delegate at a cultural festival asks: "I am looking for the Azerbaijani folk music performance. When does it start and where?" Write your full response in English.', 'Nümayəndə soruşur: "Azərbaycan xalq musiqisi çıxışını axtarıram. Nə vaxt və harada?" Tam cavabınızı ingilis dilində yazın.', NULL, NULL, '[{"name":"accurate_information","weight":0.35,"keywords":["stage","hall","starts at","time","location"]},{"name":"natural_english","weight":0.35,"keywords":["great","let me check","you are looking for","I believe","scheduled"]},{"name":"offer_further_help","weight":0.30,"keywords":["anything else","can I help","let me know","feel free"]}]'::jsonb, 1.4, 0.2, 0.0, 'Strong answers provide specific info, use natural English, and close with an offer of help.', 'Güclü cavablar konkret məlumat verir, təbii ingilis dilindən istifadə edir və yardım təklifi ilə bitir.', 'Practice full conversational exchanges for 5 common volunteer scenarios.', '5 ümumi ssenari üçün tam söhbət mübadiləsini məşq edin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000007', '33333333-3333-3333-3333-333333333333', 'medium', 'mcq', 'An athlete asks: "Is there a gym nearby we can use?" You are not sure. What do you say?', 'İdmançı soruşur: "Yaxınlıqda idman zalı varmı?" Əmin deyilsiniz. Nə deyirsiniz?', '[{"key":"A","text_en":"Yes there is one nearby — even though unsure","text_az":"Bəli, yaxınlıqda var — əmin olmadığınıza baxmayaraq"},{"key":"B","text_en":"Ignore the question","text_az":"Sualı nəzərə almayın"},{"key":"C","text_en":"That is a great question — I am not certain but let me find out for you right now","text_az":"Əmin deyiləm, amma indi sizin üçün öyrənəcəyəm"},{"key":"D","text_en":"I do not know — and leave it at that","text_az":"Bilmirəm — bununla buraxın"}]'::jsonb, 'C', NULL, 1.5, 0.0, 0.12, 'Saying I do not know but I will find out is both honest and service-oriented.', '"Bilmirəm, amma öyrənəcəyəm" həm dürüst, həm də xidmət yönümlüdür.', 'Memorize: "I am not 100% sure, but I will find out for you immediately."', 'Əzbərləyin: "100% əmin deyiləm, amma dərhal sizin üçün öyrənəcəyəm."') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000008', '33333333-3333-3333-3333-333333333333', 'hard', 'mcq', 'A partner at a reception asks about Azerbaijan''s renewable energy. This is outside your talking points. How do you respond?', 'Qəbulda tərəfdaş Azərbaycanın bərpa olunan enerjisi barədə soruşur. Bu hazırlıqlı mövzunuzdan kənardır. Necə cavab verirsiniz?', '[{"key":"A","text_en":"Make up facts to seem knowledgeable","text_az":"Bilikli görünmək üçün faktlar uydurun"},{"key":"B","text_en":"Share what you genuinely know and offer to connect them with a specialist","text_az":"Həqiqətən bildiyinizi paylaşın və mütəxəssislə əlaqələndirməyi təklif edin"},{"key":"C","text_en":"I do not know anything about that — end conversation","text_az":"Bu barədə heç nə bilmirəm — söhbəti bitirin"},{"key":"D","text_en":"Change the subject immediately","text_az":"Dərhal mövzunu dəyişin"}]'::jsonb, 'B', NULL, 2.0, 0.8, 0.10, 'Advanced English communication: acknowledge limits honestly, contribute what you know, add value by connecting.', 'Qabaqcıl ingilis ünsiyyəti: məhdudiyyətləri etiraf edin, bildiyinizi paylaşın, əlaqələndirərək dəyər əlavə edin.', 'Build a bridge-and-connect script for unfamiliar topics.', 'Tanış olmayan mövzular üçün körpü-qur-və-əlaqələndir skripti hazırlayın.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000009', '33333333-3333-3333-3333-333333333333', 'hard', 'open_ended', 'Your supervisor asks you to write a briefing email to 12 international volunteers: shift at 7am, wear official vests, 10-min team meeting at main entrance before shift. Write the email.', 'Rəhbər 12 beynəlxalq könüllüyə brifinq e-poçtu yazmağınızı istəyir: növbə saat 7:00, rəsmi jiletlər, başlanğıcdan əvvəl girişdə 10 dəq görüş. E-poçtu yazın.', NULL, NULL, '[{"name":"all_three_facts","weight":0.40,"keywords":["7am","vest","official","meeting","10 minutes","main entrance"]},{"name":"professional_tone","weight":0.30,"keywords":["Dear","Hello","team","please","regards","best"]},{"name":"clear_structure","weight":0.30,"keywords":["first","also","additionally","please note","reminder"]}]'::jsonb, 2.2, 1.2, 0.0, 'Top emails include all three facts clearly, use professional greeting/sign-off, and correct grammar.', 'Ən yaxşı e-poçtlarda hər üç fakt aydındır, peşəkar salamlama/imza var və qrammatika düzgündür.', 'Study briefing email structure: Subject → Greeting → Key facts → Call to action → Sign-off.', 'Brifinq e-poçt strukturunu öyrənin: Mövzu → Salamlama → Faktlar → Fəaliyyətə çağırış → İmza.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('e0000001-0000-0000-0000-000000000010', '33333333-3333-3333-3333-333333333333', 'hard', 'open_ended', 'A senior delegate says simultaneous translation in Room B was poor all day and delegates missed important content. They ask you to make sure this feedback reaches the right people. What do you say and do?', 'Üst səviyyəli nümayəndə B otağındakı sinxron tərcümənin bütün gün pis olduğunu və nümayəndələrin mühüm məzmunu qaçırdığını bildirir. Bu rəyin düzgün şəxslərə çatmasını istəyir. Nə deyir və edirsiniz?', NULL, NULL, '[{"name":"acknowledgment_empathy","weight":0.25,"keywords":["understand","sorry","frustrating","thank you for telling me"]},{"name":"immediate_action","weight":0.35,"keywords":["right away","immediately","contact","escalate","supervisor"]},{"name":"clear_english","weight":0.25,"keywords":["I will","let me","I will make sure","I will follow up"]},{"name":"follow_through","weight":0.15,"keywords":["follow up","let you know","update you","get back to you"]}]'::jsonb, 2.4, 1.6, 0.0, 'Best answers: empathy in clear English, immediate escalation, concrete next steps, follow-up commitment.', 'Ən yaxşı cavablar: aydın ingilis dilindəki empatiya, dərhal eskalasiya, konkret addımlar, izləmə öhdəliyi.', 'Memorize: Acknowledge → Validate → Commit to action → Give timeline → Follow up.', 'Əzbərləyin: Qəbul et → Təsdiq et → Hərəkətə öhdəlik → Vaxt çərçivəsi → İzlə.') ON CONFLICT (id) DO NOTHING;
-- =============================================================================
-- LEADERSHIP COMPETENCY (10 questions)
-- competency_id: 44444444-4444-4444-4444-444444444444
-- =============================================================================

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000001', '44444444-4444-4444-4444-444444444444', 'easy', 'mcq', 'You are leading 8 volunteers at a cultural festival. One arrives 30 minutes late and seems unmotivated. What do you do first?', 'Mədəniyyət festivalında 8 könüllüyə rəhbərlik edirsiniz. Biri 30 dəqiqə gecikir və motivasiyasız görünür. İlk olaraq nə edərsiniz?', '[{"key":"A","text_en":"Publicly reprimand them in front of the team","text_az":"Onları komanda qarşısında məzəmmət edin"},{"key":"B","text_en":"Privately check in, understand the reason, and reassign if needed","text_az":"Şəxsən yanaşın, səbəbi öyrənin və lazım olsa tapşırıqları yenidən bölüşdürün"},{"key":"C","text_en":"Ignore the situation and hope they improve","text_az":"Vəziyyəti görməzdən gəlin"},{"key":"D","text_en":"Immediately report them to the event organizer","text_az":"Dərhal təşkilatçıya bildirin"}]'::jsonb, 'B', NULL, 1.1, -1.2, 0.15, 'Effective leaders address issues privately and empathetically before escalating.', 'Effektiv liderlər problemləri şəxsən və empatiya ilə həll edirlər.', 'Practice one-on-one check-ins during low-pressure moments.', 'Az gərginlikli anlarda fərdi görüşlər keçirməyi məşq edin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000002', '44444444-4444-4444-4444-444444444444', 'easy', 'mcq', 'Before a summit, your team is visibly anxious and unsure of their roles. What is the most effective first step?', 'Sammit əvvəl komandanız narahatdır və rollarından əmin deyillər. Ən effektiv ilk addım nədir?', '[{"key":"A","text_en":"Tell them to relax and figure it out","text_az":"Rahatlaşmağı söyləyin"},{"key":"B","text_en":"Hold a quick briefing to clarify roles and answer questions","text_az":"Rolları aydınlaşdırmaq üçün qısa brifinq keçirin"},{"key":"C","text_en":"Assign the most confident volunteer to handle everyone","text_az":"Ən inamlı könüllünü hamını idarə etmək üçün təyin edin"},{"key":"D","text_en":"Delay start until everyone feels confident","text_az":"Hamı inamlı hiss edənə qədər gecikdirin"}]'::jsonb, 'B', NULL, 1.0, -1.4, 0.15, 'A pre-event briefing aligns the team, reduces anxiety, and ensures role clarity.', 'Tədbirdən əvvəl brifinq komandanı uyğunlaşdırır və narahatlığı azaldır.', 'Develop a standard 5-minute pre-event briefing template.', 'Standart 5 dəqiqəlik tədbirdən əvvəl brifinq şablonu hazırlayın.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000003', '44444444-4444-4444-4444-444444444444', 'easy', 'open_ended', 'You are a team leader at an international sports event. Describe how you would motivate your team during a long, tiring shift.', 'Beynəlxalq idman tədbirindəki komanda liderissiniz. Uzun yorucu növbədə komandasını necə motivasiya edərdiniz?', NULL, NULL, '[{"name":"recognition","weight":0.35,"keywords":["acknowledge","praise","thank","recognize","appreciate"]},{"name":"energy_management","weight":0.35,"keywords":["break","rotation","rest","schedule"]},{"name":"team_spirit","weight":0.30,"keywords":["together","morale","encourage","support"]}]'::jsonb, 1.2, -1.0, 0.0, 'Strong leaders use recognition, structured breaks, and team-building moments.', 'Güclü liderlər tanınma, strukturlaşdırılmış fasilələr və komanda ruhu anlarından istifadə edirlər.', 'Study servant leadership: prioritize team wellbeing.', 'Xidmət liderliyini öyrənin: komanda rifahını ön planda tutun.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000004', '44444444-4444-4444-4444-444444444444', 'medium', 'mcq', 'Two volunteers have a conflict over task ownership mid-event. The event is in full swing. What do you do?', 'İki könüllünüz tapşırıq sahibliyi üzərində münaqişəyə girir. Tədbir tam gücündə davam edir. Nə edirsiniz?', '[{"key":"A","text_en":"Separate them and assign to different areas, debrief after event","text_az":"Ayırın və fərqli ərazilərə göndərin, tədbirdən sonra izahat alın"},{"key":"B","text_en":"Let them resolve it themselves","text_az":"Özləri həll etsinlər"},{"key":"C","text_en":"Side with the more experienced volunteer","text_az":"Daha təcrübəli könüllünün tərəfini tutun"},{"key":"D","text_en":"Hold a mediation session mid-event","text_az":"Tədbir zamanı vasitəçilik keçirin"}]'::jsonb, 'A', NULL, 1.4, -0.2, 0.12, 'During live events, operational continuity first. Separate, continue, debrief later.', 'Canlı tədbirlərdə əməliyyat davamlılığı birinci gəlir. Ayır, davam et, sonra izah al.', 'Learn 2-minute conflict de-escalation techniques for high-pressure environments.', 'Yüksək gərginlikli mühitlər üçün 2 dəqiqəlik münaqişəni azaltma üsullarını öyrənin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000005', '44444444-4444-4444-4444-444444444444', 'medium', 'mcq', 'One capable volunteer dominates group decisions, causing quieter members to disengage. How do you address this?', 'Bacarıqlı könüllülərdən biri qrup qərarlarında üstünlük qurur, sakit üzvlər kənara çəkilir. Bunu necə həll edirsiniz?', '[{"key":"A","text_en":"Tell the dominant volunteer to stop sharing opinions","text_az":"Dominant könüllüyə fikirlərini dayandırmağı söyləyin"},{"key":"B","text_en":"Restructure discussions so every member speaks before decisions","text_az":"Hər üzv danışsın deyə müzakirələri yenidən qurun"},{"key":"C","text_en":"Remove quieter members from decision-making","text_az":"Sakit üzvləri qərar qəbulundan çıxarın"},{"key":"D","text_en":"Ignore it if team output is good","text_az":"Çıxış yaxşıdırsa, məhəl qoymayın"}]'::jsonb, 'B', NULL, 1.5, 0.1, 0.10, 'Structural changes to discussions are more effective than suppressing capable individuals.', 'Müzakirə formatlarında struktur dəyişiklikləri bacarıqlı fərdləri susdurmaqdan daha effektivdir.', 'Research facilitation techniques like structured turn-taking.', 'Strukturlaşdırılmış növbə alma kimi fasilitasiya üsullarını tədqiq edin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000006', '44444444-4444-4444-4444-444444444444', 'medium', 'open_ended', 'The organizer asks you to integrate 5 unassigned volunteers mid-event. Describe how you would do this without disrupting your existing team.', 'Təşkilatçı tədbirinin ortasında 5 tapşırıqsız könüllünü qəbul etməyinizi istəyir. Komandasını pozmadan necə inteqrasiya edərdiniz?', NULL, NULL, '[{"name":"rapid_assessment","weight":0.30,"keywords":["assess","skills","strengths","evaluate"]},{"name":"role_assignment","weight":0.35,"keywords":["assign","role","task","match","gap"]},{"name":"communication","weight":0.35,"keywords":["brief","introduce","inform","team","update"]}]'::jsonb, 1.6, 0.2, 0.0, 'Effective integration: quickly assess strengths, identify gaps, communicate changes to existing team.', 'Effektiv inteqrasiya: güclü tərəfləri tez qiymətləndirin, boşluqları müəyyənləşdirin, dəyişiklikləri çatdırın.', 'Keep a simple skills inventory format ready for rapid deployment.', 'Sürətli yerləşdirmə üçün sadə bacarıq inventarı formatını hazır saxlayın.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000007', '44444444-4444-4444-4444-444444444444', 'medium', 'open_ended', 'After a public mistake by one volunteer, team morale has dropped significantly. How do you rebuild confidence as a leader?', 'Bir könüllünün ictimai səhvindən sonra komandanızın ruhu düşüb. Lider kimi inamı necə yenidən qurarsınız?', NULL, NULL, '[{"name":"normalization","weight":0.30,"keywords":["normalize","mistake","human","learn","normal"]},{"name":"accountability","weight":0.35,"keywords":["acknowledge","responsibility","honest","transparent"]},{"name":"forward_focus","weight":0.35,"keywords":["next","plan","action","move forward","recover"]}]'::jsonb, 1.7, 0.3, 0.0, 'Rebuilding morale: acknowledge the mistake, normalize errors as learning, redirect to next actions.', 'Ruhu yenidən qurmaq: səhvi qəbul edin, xətaları normallaşdırın, növbəti hərəkətlərə yönləndirin.', 'Study crisis communication frameworks used by event leaders.', 'Hadisə liderlərinin böhran kommunikasiyası çərçivələrini öyrənin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000008', '44444444-4444-4444-4444-444444444444', 'hard', 'mcq', 'You lead 20 volunteers in 4 zones. Simultaneous reports: Zone 1 crowd control issue, Zone 3 volunteer no-show, Zone 4 ahead of schedule needs tasks. 3 minutes. Correct prioritization?', '4 zonada 20 könüllüyə rəhbərlik edirsiniz. Eyni anda: Zona 1-də izdiham, Zona 3-də könüllü gəlməyib, Zona 4 öndədir. 3 dəqiqə. Düzgün prioritet?', '[{"key":"A","text_en":"Zone 4 first (ahead, can take more), then Zone 3, then Zone 1","text_az":"Əvvəlcə Zona 4, sonra 3, sonra 1"},{"key":"B","text_en":"Zone 1 first (safety), redirect Zone 4 surplus to Zone 3, confirm Zone 4 self-manages","text_az":"Əvvəlcə Zona 1 (təhlükəsizlik), Zona 4-ün artığını Zona 3-ə, Zona 4 özünü idarə etsin"},{"key":"C","text_en":"Zone 3 first (empty post), then Zone 1, ignore Zone 4","text_az":"Əvvəlcə Zona 3, sonra 1, Zona 4-ü görməzdən gəlin"},{"key":"D","text_en":"Call supervisor and wait for instructions","text_az":"Rəhbərə zəng edib təlimat gözləyin"}]'::jsonb, 'B', NULL, 2.1, 1.0, 0.10, 'Crowd control = safety-critical, first. Zone 4 surplus solves Zone 3 gap. Two problems with one decision.', 'İzdiham nəzarəti = təhlükəsizlik, birinci. Zona 4-ün artığı Zona 3 boşluğunu həll edir. Bir qərarla iki problem.', 'Practice OODA loop: Observe, Orient, Decide, Act.', 'OODA döngüsünü məşq edin: Müşahidə, Yönəlt, Qərar ver, Hərəkət et.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000009', '44444444-4444-4444-4444-444444444444', 'hard', 'mcq', 'After a successful event, you learn two of your volunteers received rudeness complaints from attendees. How do you handle this?', 'Uğurlu tədbirın ardından iki könüllünüz barədə kobud davranış şikayətlərini öyrənirsiniz. Bunu necə həll edirsiniz?', '[{"key":"A","text_en":"Ignore it — overall success balances it out","text_az":"Görməzdən gəlin — ümumi uğur tarazlaşdırır"},{"key":"B","text_en":"Announce to the whole team that two people got complaints","text_az":"Bütün komandaya iki nəfərin şikayət aldığını elan edin"},{"key":"C","text_en":"Meet privately with each, share specific feedback, co-create improvement plan","text_az":"Hər biri ilə şəxsən görüşün, konkret rəy paylaşın, birlikdə inkişaf planı hazırlayın"},{"key":"D","text_en":"Remove them from future events immediately","text_az":"Onları dərhal gələcək tədbirlərdən çıxarın"}]'::jsonb, 'C', NULL, 2.0, 0.9, 0.08, 'Developmental feedback must be specific, private, and forward-looking.', 'İnkişaf rəyi konkret, şəxsi və gələcəyə yönəlmiş olmalıdır.', 'Study the SBI feedback model: Situation-Behavior-Impact.', 'SBI rəy modelini öyrənin: Vəziyyət-Davranış-Təsir.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('40000001-0000-0000-0000-000000000010', '44444444-4444-4444-4444-444444444444', 'hard', 'open_ended', 'You are asked to build a leadership pipeline for a national volunteer program. How would you identify, develop, and retain future team leaders from 50 active volunteers?', 'Milli könüllü proqramı üçün liderlik boru xətti qurmağa dəvət edildiniz. 50 aktiv könüllüdən gələcək liderləri necə müəyyən edər, inkişaf etdirər və saxlayardınız?', NULL, NULL, '[{"name":"identification","weight":0.30,"keywords":["identify","criteria","observe","track","performance"]},{"name":"development","weight":0.40,"keywords":["mentor","train","shadow","rotate","develop"]},{"name":"retention","weight":0.30,"keywords":["recognize","reward","career","grow","keep"]}]'::jsonb, 2.3, 1.5, 0.0, 'A pipeline needs: systematic identification, structured development (mentoring, shadowing), and retention mechanisms.', 'Boru xətti tələb edir: sistemli müəyyənləşdirmə, strukturlaşdırılmış inkişaf (mentorluq, kölgə etmə) və saxlama mexanizmləri.', 'Study talent pipeline frameworks from UNICEF or Red Cross volunteer programs.', 'UNICEF və ya Qırmızı Xaç könüllü proqramlarından istedadlı boru xətti çərçivələrini öyrənin.') ON CONFLICT (id) DO NOTHING;

-- =============================================================================
-- EVENT PERFORMANCE COMPETENCY (10 questions)
-- competency_id: 55555555-5555-5555-5555-555555555555
-- =============================================================================

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000001', '55555555-5555-5555-5555-555555555555', 'easy', 'mcq', 'Your shift starts at 09:00 but you arrive at 08:45. Your supervisor has not assigned your station yet. What do you do?', 'Növbəniz 09:00-da başlayır, siz 08:45-də gəlirsiniz. Nəzarətçi hələ stansiya təyin etməyib. Nə edirsiniz?', '[{"key":"A","text_en":"Wait at the entrance","text_az":"Girişdə gözləyin"},{"key":"B","text_en":"Find your supervisor, confirm assignment, help with setup","text_az":"Nəzarətçini tapın, tapşırığı təsdiqləyin, quraşdırmaya kömək edin"},{"key":"C","text_en":"Start helping wherever without checking in","text_az":"Yoxlama olmadan kömək etməyə başlayın"},{"key":"D","text_en":"Return at exactly 09:00","text_az":"Dəqiq 09:00-da qayıdın"}]'::jsonb, 'B', NULL, 1.1, -1.3, 0.15, 'Proactive communication and initiative before shift formally begins demonstrates reliability.', 'Növbədən əvvəl proaktiv ünsiyyət və təşəbbüs etibarlılığı nümayiş etdirir.', 'Arrive 15 minutes early and use that time for orientation.', 'Hər tədbirə 15 dəqiqə əvvəl gəlin və bu vaxtı oriyentasiya üçün istifadə edin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000002', '55555555-5555-5555-5555-555555555555', 'easy', 'mcq', 'A visitor asks a question you do not know the answer to. The info point is 200m away and you cannot leave your post. What do you do?', 'Ziyarətçi cavabını bilmədiyiniz sual verir. Məlumat nöqtəsi 200m uzaqdadır, postu tərk edə bilmirsiniz. Nə edirsiniz?', '[{"key":"A","text_en":"Tell them you do not know, suggest finding someone else","text_az":"Bilmədiyinizi söyləyin, başqasını tapmağı təklif edin"},{"key":"B","text_en":"Make up a plausible answer","text_az":"İnandırıcı cavab uydurun"},{"key":"C","text_en":"Acknowledge, radio a colleague, keep visitor informed while getting answer","text_az":"Qəbul edin, həmkara radio/zəng edin, cavabı alarkən ziyarətçini məlumatlandırın"},{"key":"D","text_en":"Leave your post to walk them to the info point","text_az":"Ziyarətçini məlumat nöqtəsinə aparmaq üçün postu tərk edin"}]'::jsonb, 'C', NULL, 1.0, -1.1, 0.15, 'Best response maintains post while actively solving the problem through your network.', 'Ən yaxşı cavab şəbəkəniz vasitəsilə problemi həll edərkən postu qoruyur.', 'Memorize your event radio protocol and key contact numbers.', 'Tədbirinin radio protokolunu və əsas əlaqə nömrələrini yadda saxlayın.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000003', '55555555-5555-5555-5555-555555555555', 'easy', 'open_ended', 'Describe how you personally prepare the night before a full-day volunteer shift at a major event.', 'Böyük tədbirdə tam günlük növbədən bir gecə əvvəl necə hazırlaşırsınız?', NULL, NULL, '[{"name":"logistics","weight":0.35,"keywords":["sleep","rest","route","transport","arrive","early"]},{"name":"information","weight":0.35,"keywords":["brief","schedule","role","read","review","plan"]},{"name":"physical_readiness","weight":0.30,"keywords":["eat","hydrate","clothes","shoes","kit"]}]'::jsonb, 1.2, -1.2, 0.0, 'High-performing volunteers treat pre-event preparation as part of the job.', 'Yüksək performanslı könüllülər tədbirden əvvəl hazırlığı işin bir hissəsi kimi qəbul edirlər.', 'Create a personal pre-event checklist template (20 minutes the night before).', 'Şəxsi tədbirden əvvəl yoxlama siyahısı hazırlayın (gecədən əvvəl 20 dəqiqə).') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000004', '55555555-5555-5555-5555-555555555555', 'medium', 'mcq', 'You manage the accreditation desk. A long queue forms and the printer breaks. The next 20 attendees are pre-registered but cannot get badges. What do you do?', 'Akkreditasiya masasını idarə edirsiniz. Uzun növbə yaranıb, printer xarab olub. 20 iştirakçı qeydiyyatdandır, lakin nişan ala bilmir. Nə edirsiniz?', '[{"key":"A","text_en":"Stop the line and wait for IT to fix the printer","text_az":"Sıranı dayandırın və İT-ni gözləyin"},{"key":"B","text_en":"Verify digitally, provide temp handwritten pass, notify supervisor","text_az":"Rəqəmsal yoxlayın, müvəqqəti əl ilə yazılmış icazə verin, nəzarətçini xəbərdar edin"},{"key":"C","text_en":"Turn people away until printer is fixed","text_az":"Printer düzəlnə kimi insanları geri göndərin"},{"key":"D","text_en":"Let everyone in without verification","text_az":"Hamını doğrulama olmadan buraxın"}]'::jsonb, 'B', NULL, 1.6, 0.0, 0.12, 'Problem-solving under pressure: improvise a compliant workaround maintaining service and security.', 'Təzyiq altında problem həlli: xidmət və təhlükəsizliyi qoruyan müvəqqəti həll tapın.', 'Identify single points of failure before they occur at every event.', 'Hər tədbirde tək uğursuzluq nöqtələrini əvvəlcədən müəyyən edin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000005', '55555555-5555-5555-5555-555555555555', 'medium', 'mcq', 'You are simultaneously responsible for guiding a VIP group, managing a queue, and answering radio calls. How?', 'Eyni anda VİP qrupuna rəhbərlik, növbə idarəsi və radio cavabı. Necə?', '[{"key":"A","text_en":"Focus entirely on VIP — highest priority","text_az":"Tamamilə VİP-ə diqqət — ən yüksək prioritet"},{"key":"B","text_en":"Triage: hand off queue to nearby volunteer, answer radio briefly, then VIP","text_az":"Triage: növbəni yaxınlıqdakı könüllüyə verin, radioya qısaca cavab, sonra VİP"},{"key":"C","text_en":"Ignore radio while handling physical tasks","text_az":"Fiziki tapşırıqları edərkən radionu görməzdən gəlin"},{"key":"D","text_en":"Stop and ask coordinator which task first","text_az":"Koordinatordan hansının əvvəl olduğunu soruşun"}]'::jsonb, 'B', NULL, 1.8, 0.2, 0.10, 'Rapid delegation and triage: hand off lower-priority tasks while maintaining primary responsibility.', 'Sürətli nümayəndəlik və triage: əsas məsuliyyəti qoruyarkən aşağı prioritetli tapşırıqları ötürün.', 'Practice the delegation reflex: before taking a third task, who can handle task two?', 'Nümayəndəlik refleksini məşq edin: üçüncü tapşırığı almadan əvvəl ikincini kim ala bilər?') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000006', '55555555-5555-5555-5555-555555555555', 'medium', 'open_ended', 'Your area falls 45 minutes behind schedule due to a technical delay outside your control. How do you minimize disruption for attendees?', 'Nəzarətinizdən kənar texniki gecikmə səbəbindən əraziniz cədvəldən 45 dəqiqə geri qalır. Pozuntunu necə minimuma endirərdiniz?', NULL, NULL, '[{"name":"communication","weight":0.35,"keywords":["inform","announce","update","attendees","transparent"]},{"name":"improvisation","weight":0.35,"keywords":["alternative","activity","entertain","fill","improvise"]},{"name":"coordination","weight":0.30,"keywords":["escalate","supervisor","team","coordinate","report"]}]'::jsonb, 1.7, 0.1, 0.0, 'Managing delays: transparent communication, creative gap-filling, and upward escalation.', 'Gecikməni idarə etmək: şəffaf ünsiyyət, yaradıcı boşluq doldurmaq və yuxarıya eskalasiya.', 'Study how major events handle technical delays with pre-prepared holding content.', 'Böyük tədbirlərin texniki gecikməni hazırlanmış gözləmə məzmunu ilə necə həll etdiyini öyrənin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000007', '55555555-5555-5555-5555-555555555555', 'medium', 'open_ended', '80 volunteers arrive in a 15-minute window for check-in and the system is slow. How would you prevent a bottleneck?', '80 könüllü 15 dəqiqə ərzində qeydiyyata gəlir və sistem yavaşdır. Tıxacın qarşısını necə alardınız?', NULL, NULL, '[{"name":"process_design","weight":0.40,"keywords":["lane","queue","split","alphabetical","group"]},{"name":"resource_use","weight":0.35,"keywords":["help","colleague","extra","second","parallel"]},{"name":"communication","weight":0.25,"keywords":["announce","direct","guide","signal","sign"]}]'::jsonb, 1.6, 0.3, 0.0, 'Preventing bottlenecks: split queues, parallel processing, active flow management, extra hands.', 'Tıxacı önləmək: növbələri bölmək, paralel emal, aktiv axın idarəsi, əlavə kömək.', 'Study operations basics like Little''s Law for queue management.', 'Növbə idarəetməsi üçün Little qanunu kimi əsas əməliyyat biliklərini öyrənin.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000008', '55555555-5555-5555-5555-555555555555', 'hard', 'mcq', 'During a closing ceremony, unexpected power outage hits your zone. 300 attendees, no lighting, no sound. You have a radio and flashlight. First 60 seconds?', 'Bağlanış mərasimində elektrik kəsildi. 300 iştirakçı, işıq yoxdur. Radionuz və fənəriniz var. İlk 60 saniyə?', '[{"key":"A","text_en":"Radio the outage, illuminate nearest exit with flashlight, calmly instruct attendees to stay in place","text_az":"Radio ilə bildirin, fənərlə çıxışı işıqlandırın, sakit şəkildə yerli-yerində qalmağı tapşırın"},{"key":"B","text_en":"Find the electrical panel yourself","text_az":"Elektrik panelini özünüz axtarın"},{"key":"C","text_en":"Wait for official instructions","text_az":"Rəsmi təlimatı gözləyin"},{"key":"D","text_en":"Direct everyone to evacuate immediately","text_az":"Hamını dərhal təxliyə etməyə yönəldin"}]'::jsonb, 'A', NULL, 2.2, 1.2, 0.08, 'First 60 seconds: safety communication and crowd stabilization over problem-solving.', 'İlk 60 saniyə: problem həllindən daha çox təhlükəsizlik ünsiyyəti və izdiham sabitləşdirməsi.', 'Take a crowd safety management course — many are free online.', 'İzdiham təhlükəsizliyi kursu keçin — bir çox pulsuz onlayn mövcuddur.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000009', '55555555-5555-5555-5555-555555555555', 'hard', 'mcq', 'You manage the transport desk alone. Three delegates arrive simultaneously: lost badge, late shuttle, last-minute change. All frustrated. What do you do?', 'Nəqliyyat masasını tək idarə edirsiniz. Üç nümayəndə eyni anda gəlir: itirilmiş nişan, gecikmiş servis, son dəqiqə dəyişiklik. Hamısı məyusdur. Nə edirsiniz?', '[{"key":"A","text_en":"Handle them one by one in arrival order","text_az":"Gəliş qaydası ilə bir-bir idarə edin"},{"key":"B","text_en":"Triage: acknowledge all three, radio the shuttle issue, ask badge person to wait 90 sec, handle transport change","text_az":"Triage: üçünü qəbul edin, servis üçün radio, nişan üçün 90 san gözlətmə, nəqliyyat dəyişikliyini həll edin"},{"key":"C","text_en":"Ask them to form a queue","text_az":"Növbə yaratmağı xahiş edin"},{"key":"D","text_en":"Call supervisor and hand all three over","text_az":"Rəhbərə zəng edib üçünü də verin"}]'::jsonb, 'B', NULL, 2.1, 1.1, 0.10, 'Multi-stakeholder triage: simultaneous acknowledgment, smart delegation, sequenced resolution.', 'Çoxtərəfli triage: eyni anda qəbul, ağıllı nümayəndəlik, ardıcıl həll.', 'Study service recovery from hospitality: acknowledge, empathize, resolve.', 'Qonaqsevərlikdən xidmət bərpasını öyrənin: qəbul et, empatiya qur, həll et.') ON CONFLICT (id) DO NOTHING;

INSERT INTO public.questions (id, competency_id, difficulty, type, scenario_en, scenario_az, options, correct_answer, expected_concepts, irt_a, irt_b, irt_c, feedback_en, feedback_az, development_tip_en, development_tip_az) VALUES
('50000001-0000-0000-0000-000000000010', '55555555-5555-5555-5555-555555555555', 'hard', 'open_ended', 'After a 10-hour festival shift, write a structured debrief: what went well, what failed, what you would do differently, what you need from the organizing team.', '10 saatlıq festivaldan sonra strukturlaşdırılmış brifinq yazın: nə yaxşı getdi, nə uğursuz oldu, nəyi dəyişərdiniz, təşkilatdan nəyə ehtiyacınız var.', NULL, NULL, '[{"name":"self_reflection","weight":0.30,"keywords":["went well","success","strength","achieved"]},{"name":"critical_analysis","weight":0.35,"keywords":["failed","problem","gap","mistake"]},{"name":"actionable_improvement","weight":0.35,"keywords":["differently","next time","suggest","request","recommend"]}]'::jsonb, 2.3, 1.6, 0.0, 'Elite volunteers treat every event as a learning system with structured debrief.', 'Elit könüllülər hər hadisəyə strukturlaşdırılmış brifinq ilə öyrənmə sistemi kimi baxır.', 'Build a personal debrief template and use after every role, even short ones.', 'Şəxsi brifinq şablonu hazırlayın və qısa olanlar da daxil olmaqla hər roldan sonra istifadə edin.') ON CONFLICT (id) DO NOTHING;
